function reportDateOf(r){ if(!r)return null; return isoToDate(r.reportDateISO) || looseDate(r.reportDate); }
function expectedClose(o,r){ const base=reportDateOf(r); const w=CLOSE_DAYS[o.timeline]; return (base&&w)?addDays(base,w):null; }
function effectiveClose(o,r){ return looseDate(o.dueDate) || expectedClose(o,r); }  // manual target overrides computed
function obsAge(o,r){ const base=reportDateOf(r); if(!base)return null; const end=(o.status==="Closed"&&isoToDate(o.closedDateISO))?isoToDate(o.closedDateISO):today0(); return Math.max(0,daysBetween(base,end)); }
function isOverdueObs(o,r){ if(o.status==="Closed")return false; const c=effectiveClose(o,r); return !!(c && today0()>c); }
function ageBucket(n){ if(n==null)return "—"; if(n<=30)return "0–30 days"; if(n<=60)return "31–60 days"; if(n<=90)return "61–90 days"; return ">90 days"; }
const AGE_BUCKETS = ["0–30 days","31–60 days","61–90 days",">90 days"];
const CLOSE_BUCKETS = ["Overdue","≤ 2 weeks","2–4 weeks","1–3 months","> 3 months"];
const CLOSEB_HEX = {"Overdue":"#b00020","≤ 2 weeks":"#e8590c","2–4 weeks":"#c9a300","1–3 months":"#2c5f8a","> 3 months":"#2e7d32"};
function daysToClose(o,r){ const c=effectiveClose(o,r); return c?daysBetween(today0(),c):null; }   // +ve = days remaining, -ve = overdue
function closeBucket(d){ if(d==null)return null; if(d<0)return "Overdue"; if(d<=14)return "≤ 2 weeks"; if(d<=30)return "2–4 weeks"; if(d<=90)return "1–3 months"; return "> 3 months"; }
function isoNow(){ const d=new Date(); return d.getFullYear()+"-"+("0"+(d.getMonth()+1)).slice(-2)+"-"+("0"+d.getDate()).slice(-2); }
function stampClosed(o,status){ if(status==="Closed"){ if(!o.closedDateISO) o.closedDateISO=isoNow(); } else { o.closedDateISO=""; } }
