function go(v,opts={}){
  if(v==="newobs"){ modalNewObs(); return; }
  if(v==="insights"){ trackerMode="insights"; v="tracker"; }
  const gated=["dashboard","audits","tracker","auditra","fraud","process","external","iasa","approvals","myobs","settings","auditlog","guide"];
  if(gated.includes(v) && !canAccessView(v)){ go(window.AMS_USER&&window.AMS_USER.role==="action_owner"?"myobs":"dashboard"); return; }
  view=v;
  curProc=null;
  if(opts.audit!==undefined) curAudit=opts.audit;
  if(opts.report!==undefined) curReport=opts.report;
  if(opts.obs!==undefined) curObs=opts.obs;
  else if(v!=="observation" && v!=="sopupdate") curObs=null;
  if(opts.unit!==undefined) curRaUnit=opts.unit;
  if(opts.fraud!==undefined) curFraud=opts.fraud;
  document.querySelectorAll("#nav button").forEach(b=>b.classList.toggle("active",b.dataset.view===v && v!=="report" && v!=="observation" && v!=="sopupdate" && v!=="audit" && v!=="raunit" && v!=="fraudrisk"));
  render();
}
