let bannerDismissed=false;
function backupBanner(){
  if(!isHeadUser()) return "";
  const hasData = (DB.audits&&DB.audits.length) || (DB.fraudRisks||[]).length || (DB.auditUniverse||[]).length || (DB.processReviews||[]).length;
  if(!hasData || bannerDismissed) return "";
  const last=DB.lastBackup?isoToDate(DB.lastBackup):null;
  const days=last?daysBetween(last,today0()):null;
  if(days!=null && days<7) return "";
  const msg = last? `It's been ${days} day${days!==1?"s":""} since your last backup.` : `You haven't backed up your data yet.`;
  return `<div style="background:#fdf6e3;border-bottom:1px solid #f0d98a;padding:9px 26px;display:flex;align-items:center;gap:12px;font-size:13px;color:#7a5b00">
    <span>⚠ ${msg} Download a backup regularly.</span>
    <button class="btn sm" onclick="exportData()">⤓ Download backup now</button>
    <div style="flex:1"></div>
    <button class="btn ghost sm" style="color:#7a5b00" onclick="bannerDismissed=true;document.getElementById('banner').innerHTML='';">Dismiss</button>
  </div>`;
}
function render(){
  const org=DB.org||"Internal Audit";
  const _on=document.getElementById("orgName"); if(_on) _on.textContent=org;
  const _lg=document.getElementById("brandLogo"); if(_lg){ const s=logoSrc(); if(s){ _lg.src=s; _lg.style.display="block"; } else { _lg.style.display="none"; } }
  const _b=document.getElementById("banner"); if(_b) _b.innerHTML=backupBanner();
  const C=document.getElementById("content");
  const T=document.getElementById("pageTitle");
  const A=document.getElementById("topActions");
  A.innerHTML=""; setTopSearch(""); setTopBack("");
  if(window.AMS_USER && window.AMS_USER.role==="action_owner" && !["myobs","observation","dashboard"].includes(view)){ view="myobs"; }
  if(view==="dashboard" && isActionOwner()){ T.textContent=pageTitleFor("dashboard"); C.innerHTML=viewOwnerDashboard(); }
  else if(view==="dashboard"){ T.textContent=pageTitleFor("dashboard"); A.innerHTML=`<button class="btn sec sm" onclick="exportDashboard()">⤓ Export dashboard</button><button class="btn sec sm" onclick="modalCaeReport()">⤓ Quarterly BAC report</button>`; C.innerHTML=viewDashboard(); }
  else if(view==="auditra"){ T.textContent=pageTitleFor("auditra"); A.innerHTML=isStaff()?`${iconBtn("modalRADownload()","⤓","Download")}`:(auditUniverse().length?`${iconBtn("modalRADownload()","⤓","Download")}<button class="btn sm" onclick="modalNewAuditPlan()">+ New audit plan</button>`:`<button class="btn sm dark ai-generate-btn" onclick="modalRAPrompt()">Generate audit universe</button>`); C.innerHTML=viewAuditRA(); }
  else if(view==="raunit"){ renderRaUnit(C,T,A); }
  else if(view==="fraudrisk"){ renderFraudRisk(C,T,A); }
  else if(view==="fraud"){ T.textContent=pageTitleFor("fraud"); A.innerHTML=`${btnDownload("modalFraudDownload()","Download")}${isStaff()?"":`<button class="btn sm dark ai-generate-btn" onclick="modalFraudPrompt()">Generate fraud risks</button><button class="btn sm" onclick="modalFraud()">+ Add fraud risk</button>`}`; C.innerHTML=viewFraud(); }
  else if(view==="external"){ T.textContent=pageTitleFor("external"); A.innerHTML=`<button class="btn sec sm" onclick="exportExternal()">⤓ Status report (Word)</button><button class="btn sm dark" onclick="modalExtImport()">⤒ Import findings</button><button class="btn sm" onclick="modalExt()">+ Add finding</button>`; C.innerHTML=viewExternal(); }
  else if(view==="iasa"){ T.textContent=pageTitleFor("iasa"); A.innerHTML=`<button class="btn sec sm" onclick="exportIASA()">⤓ Self-assessment (Word)</button><button class="btn sm dark ai-generate-btn" onclick="modalIASAPrompt()">Generate assessment</button>`; C.innerHTML=viewIASA(); }
  else if(view==="audits"){
    T.textContent=pageTitleFor("audits");
    setTopSearch(`<input id="afq" class="topbar-search" value="${esc(auditFilter.q||"")}" placeholder="Search audits &amp; reports…" oninput="auditFilter.q=this.value;refreshAuditList()">`);
    A.innerHTML=isStaff()?"":`<button class="btn" onclick="modalAudit()">+ New Audit</button>`;
    C.innerHTML=viewAudits();
  }
  else if(view==="audit"){ renderAudit(C,T,A); }
  else if(view==="report"){ renderReport(C,T,A); }
  else if(view==="observation"){ renderObservation(C,T,A); }
  else if(view==="sopupdate"){ renderSopUpdate(C,T,A); }
  else if(view==="tracker"){
    T.textContent=pageTitleFor("tracker");
    A.innerHTML=trackerMode==="insights"
      ? `<button class="btn sec sm" onclick="exportInsights()">⤓ Export insights</button>`
      : `<button class="btn sec sm" onclick="exportTracker()">⤓ Export tracker</button>`;
    C.innerHTML=trackerTabs()+(trackerMode==="insights"?viewInsights():viewTracker());
  }
  else if(view==="process"){ T.textContent=pageTitleFor("process"); const pp=curProc?procList().find(x=>x.id===curProc):null; A.innerHTML = pp? `<button class="btn sec sm" onclick="curProc=null;render()">← All reviews</button><button class="btn sec sm" onclick="exportProc('${pp.id}')">⤓ Export (Word)</button><button class="btn sm" onclick="modalProcMeta('${pp.id}')">Edit details</button>` : `<button class="btn sm" onclick="modalProcNew()">+ New review</button>`; C.innerHTML=viewProcess(); }
  else if(view==="guide"){ T.textContent=pageTitleFor("guide"); C.innerHTML=viewGuide(); }
  else if(view==="settings"){
    if(!canAccessView("settings")){ go("dashboard"); return; }
    T.textContent=pageTitleFor("settings");
    A.innerHTML=`<button class="btn sec sm" onclick="exportData()">⤓ Download backup</button><label class="btn sec sm" style="display:inline-block;margin:0">⤒ Import backup<input type="file" accept="application/json" style="display:none" onchange="importData(event)"></label>`;
    C.innerHTML=viewSettings();
  }
  else if(view==="auditlog"){
    if(!canAccessView("auditlog")){ go("dashboard"); return; }
    T.textContent=pageTitleFor("auditlog");
    A.innerHTML=`<button class="btn sec sm" onclick="refreshAuditLog(1)">Refresh</button>`;
    C.innerHTML=viewAuditLog();
    refreshAuditLog(_auditLogCache.page||1);
  }
  else if(view==="approvals"){
    if(!canAccessView("approvals")){ go("dashboard"); return; }
    T.textContent=pageTitleFor("approvals");
    C.innerHTML=viewApprovals();
  }
  else if(view==="myobs"){
    if(!canAccessView("myobs")){ go("dashboard"); return; }
    T.textContent=pageTitleFor("myobs");
    C.innerHTML=viewMyObs();
  }
  else {
    T.textContent=pageTitleFor(view)||"AuditLens";
    C.innerHTML=`<div class="empty">This section is not available.</div>`;
  }
  updateApprovalsBadge();
  renderNotifBell();
}

/* ============================ DASHBOARD ============================ */
function viewDashboard(){
  const obs=allObs();
  const total=obs.length;
  const nAudits=DB.audits.length;
  const nReports=DB.audits.reduce((s,a)=>s+a.reports.length,0);
  const HEX={Critical:"#7a0012",High:"#b00020",Moderate:"#e8590c",Low:"#2e7d32","Process Improvement":"#2c5f8a"};
  const TLC={"Immediate":"#b00020","Short-term":"#c98a00","Long-term":"#2c5f8a"};
  const byC=zc(); obs.forEach(o=>byC[o.criticality]++);
  const open=obs.filter(o=>o.status!=="Closed").length, closed=total-open;
  const keyExp=obs.filter(o=>(o.criticality==="Critical"||o.criticality==="High")&&o.status!=="Closed").length;
  const remRate=total?Math.round(closed/total*100):0;
  const overall=worstKey(byC);
  const tl={"Immediate":0,"Short-term":0,"Long-term":0,Unspecified:0};
  obs.filter(o=>o.status!=="Closed").forEach(o=>{ tl[TIMELINES.includes(o.timeline)?o.timeline:"Unspecified"]++; });
  const byArea={}; obs.forEach(o=>{ const k=o._a.area||o._a.name; (byArea[k]=byArea[k]||zct())[o.criticality]++; byArea[k].t++; });
  const areaRows=Object.entries(byArea).sort((a,b)=>(b[1].Critical*100+b[1].High*10+b[1].t)-(a[1].Critical*100+a[1].High*10+a[1].t));
  const critical=obs.filter(o=>(o.criticality==="Critical"||o.criticality==="High")&&o.status!=="Closed").sort((a,b)=>CRITS.indexOf(a.criticality)-CRITS.indexOf(b.criticality));
  const segs=CRITS.map(c=>({value:byC[c],color:HEX[c]}));
  const openObs=obs.filter(o=>o.status!=="Closed");
  const closeB={}; CLOSE_BUCKETS.forEach(b=>closeB[b]=0); let closeNoDate=0; const watchlist=[];
  openObs.forEach(o=>{ const d=daysToClose(o,o._r); if(d==null){ closeNoDate++; return; } closeB[closeBucket(d)]++; if(d<=14) watchlist.push({o,d}); });
  watchlist.sort((a,b)=>a.d-b.d);
  const overdueN=closeB["Overdue"];
  const maxCloseB=Math.max(1,...CLOSE_BUCKETS.map(b=>closeB[b]));
  const repeats=obs.filter(o=>o.isRepeat);
  const repeatOpen=repeats.filter(o=>o.status!=="Closed").length;
  const firstName=(window.AMS_USER&&window.AMS_USER.name?window.AMS_USER.name:DB.signOffName||"Awa Michael").trim().split(/\s+/)[0]||"there";
  const roleTitle=window.AMS_USER&&window.AMS_USER.role==="head_of_audit"?"Head of Audit":(window.AMS_USER&&window.AMS_USER.department?window.AMS_USER.department:(DB.signOffTitle||"Head, Internal Audit"));

  return `
  <div class="dash-welcome anim-fade-in">
    <div class="dash-welcome-text">
      <h1>Welcome, ${esc(firstName)}</h1>
      <p class="dash-welcome-role">${esc(roleTitle)}</p>
    </div>
    <div class="spacer"></div>
    <button class="btn" onclick="modalNewObs()">+ New Observation</button>
  </div>

  <div class="dash-kpis">
    ${kpi("base","Audits",nAudits,nReports+" report"+(nReports!==1?"s":""),"audit")}
    ${kpi("accent","Observations",total,open+" open · "+closed+" closed","obs")}
    ${kpi("warn","Key exposures",keyExp,"open Critical &amp; High","alert")}
    ${kpi("good","Remediation rate",remRate+"%",closed+" of "+total+" closed","check")}
  </div>

  <div class="dash2">
    <div class="card chart-card anim-fade-in anim-d2"><div class="seclabel">Observations by criticality</div>
      <div class="donutwrap">${donut(segs,total,"total")}
        <div class="legend" style="flex:1">${CRITS.map(c=>`<div class="li"><span class="dot" style="background:${HEX[c]}"></span><span class="lname">${c}</span><span class="lval">${byC[c]}</span><span class="lpct">${total?Math.round(byC[c]/total*100):0}%</span></div>`).join("")}</div>
      </div>
    </div>
    <div class="card anim-fade-in anim-d3"><div class="seclabel">Due status · open observations</div>
      <div class="tline">
        <div class="tcell tcell-overdue"><div class="tn">${closeB["Overdue"]}</div><div class="tl">Overdue</div></div>
        <div class="tcell tcell-watch"><div class="tn">${closeB["≤ 2 weeks"]}</div><div class="tl">Watchlist · ≤2 wks</div></div>
        <div class="tcell tcell-track"><div class="tn">${closeB["2–4 weeks"]+closeB["1–3 months"]+closeB["> 3 months"]}</div><div class="tl">On track</div></div>
      </div>
      <div class="hint" style="margin-top:11px">By expected close date.${closeNoDate?` ${closeNoDate} open observation(s) have no expected close date (set a target date or timeline + report date).`:""}</div>
    </div>
  </div>

  <div class="card anim-fade-in anim-d3"><div class="seclabel">Risk by process / department</div>
      ${areaRows.length?`<table style="margin-top:-2px"><thead><tr><th>Area</th>${CRITS.map(c=>`<th style="text-align:center" title="${c}">${({Critical:"Crit",High:"High",Moderate:"Mod",Low:"Low","Process Improvement":"PI"})[c]}</th>`).join("")}<th style="text-align:right">Total</th></tr></thead><tbody>
        ${areaRows.slice(0,6).map(([k,v])=>`<tr><td>${esc(k)}</td>
          ${CRITS.map(c=>`<td style="text-align:center;color:${HEX[c]};font-weight:${v[c]?700:400}">${v[c]||"·"}</td>`).join("")}
          <td style="text-align:right"><b>${v.t}</b></td></tr>`).join("")}
      </tbody></table>${areaRows.length>6?`<div class="hint" style="margin-top:8px">Showing top 6 of ${areaRows.length} areas.</div>`:""}`:`<div class="empty">No observations yet.</div>`}
  </div>

  <div class="dash2 anim-fade-in anim-d4">
    <div class="card obs-close-card">
      <div class="card-head">
        <div>
          <div class="seclabel" style="margin:0">Open observations</div>
          <div class="card-sub">Expected close timeline across the portfolio</div>
        </div>
        <div class="obs-close-stats">
          <span class="obs-close-stat overdue">${overdueN} overdue</span>
          <span class="obs-close-stat watch">${closeB["≤ 2 weeks"]} due ≤2 wks</span>
          <span class="obs-close-stat track">${closeB["2–4 weeks"]+closeB["1–3 months"]+closeB["> 3 months"]} on track</span>
        </div>
      </div>
      <div class="obs-close-grid">
        ${CLOSE_BUCKETS.map(b=>{
          const cls=b==="Overdue"?"overdue":b==="≤ 2 weeks"?"soon":b==="2–4 weeks"?"mid":b==="1–3 months"?"plan":"ok";
          return `<div class="obs-close-item ${cls}"><div class="val">${closeB[b]}</div><div class="lbl">${esc(b)}</div></div>`;
        }).join("")}
      </div>
      ${closeNoDate?`<div class="hint" style="margin-top:14px">${closeNoDate} open observation(s) have no expected close date. Set a target date or timeline plus report date.</div>`:""}
    </div>
    <div class="card"><div class="seclabel">Repeat findings</div>
      <div class="row" style="align-items:baseline;gap:8px"><div style="font-size:34px;font-weight:700;color:#6b3fa0">${repeats.length}</div><div class="hint">recurring from prior audits · ${repeatOpen} still open</div></div>
      ${repeats.length?`<table style="margin-top:8px"><thead><tr><th>Observation</th><th>Audit</th><th>Prior ref</th><th>Status</th></tr></thead><tbody>
        ${repeats.slice(0,5).map(o=>`<tr><td>${esc(o.title)}</td><td>${esc(o._a.name)}</td><td>${esc(o.repeatOf||"—")}</td><td>${statusPill(o.status)}</td></tr>`).join("")}</tbody></table>${repeats.length>5?`<div class="hint" style="margin-top:6px">Showing 5 of ${repeats.length}.</div>`:""}`
        :`<div class="hint" style="margin-top:8px">No repeat findings flagged yet. Tick “Repeat observation” when editing an observation.</div>`}
    </div>
  </div>

  <div class="card">
    <div class="seclabel">Watchlist — open observations due within 2 weeks</div>
    ${watchlist.length?`<div class="hint" style="margin:-2px 0 8px">Click a row to see the details and add notes.</div><table><thead><tr><th>Expected close</th><th>Criticality</th><th>Observation</th><th>Audit / Area</th><th>Action owner</th><th>Status</th><th>Notes</th></tr></thead><tbody>`+
      watchlist.slice(0,15).map(({o,d})=>{ const ec=effectiveClose(o,o._r); const isOpen=!!dashWatchOpen[o.id]; const nc=(o.notes||[]).length; return `<tr class="watch-row${isOpen?" open":""}" onclick="toggleWatch('${o.id}',event)" title="Click for details" aria-expanded="${isOpen}">
        <td>${ec?fmtDate(ec):"—"} ${d<0?`<span class="pill c-Critical">${-d}d overdue</span>`:`<span class="pill c-Moderate">${d}d left</span>`}</td>
        <td><span class="pill c-${ck(o.criticality)}">${o.criticality}</span></td>
        <td><span class="watch-caret" aria-hidden="true">${isOpen?"▾":"▸"}</span> <b>${esc(o.title)}</b></td>
        <td>${esc(o._a.name)}<div class="hint">${esc(o._a.area||"")}</div></td>
        <td>${esc(o.owner||"—")}</td>
        <td>${statusPill(o.status)}</td>
        <td onclick="event.stopPropagation()"><button class="btn ghost sm watch-note-btn" onclick="modalAddNote('${o._a.id}','${o._r.id}','${o.id}')" title="Add / view notes">${nc?`<span class="pill note-count">${nc} note${nc!==1?"s":""}</span>`:`+ Add note`}</button></td>
      </tr>`+(isOpen?`<tr class="watch-detail-row"><td colspan="7">${watchDetailHTML(o)}</td></tr>`:""); }).join("")+`</tbody></table>`+(watchlist.length>15?`<div class="hint" style="margin-top:8px">Showing 15 of ${watchlist.length}.</div>`:"")
      :`<div class="empty">No open observations due within 2 weeks.</div>`}
  </div>

  <div class="card">
    <div class="seclabel">Top open Critical &amp; High exposures</div>
    ${critical.length?`<table><thead><tr><th>Criticality</th><th>Observation</th><th>Audit / Area</th><th>Action owner</th><th>Timeline</th><th>Status</th></tr></thead><tbody>`+
      critical.slice(0,12).map(o=>`<tr>
        <td><span class="pill c-${ck(o.criticality)}">${o.criticality}</span></td>
        <td><b>${esc(o.title)}</b></td>
        <td>${esc(o._a.name)}<div class="hint">${esc(o._a.area||"")}</div></td>
        <td>${esc(o.owner||"—")}</td>
        <td class="timeline-cell">${tlPill(o.timeline)}</td>
        <td>${statusPill(o.status)}</td>
      </tr>`).join("")+`</tbody></table>`+(critical.length>12?`<div class="hint" style="margin-top:8px">Showing 12 of ${critical.length} open key exposures.</div>`:"")
      :`<div class="empty">No open Critical or High observations.</div>`}
  </div>`;
}
/* ---- Watchlist inline details + notes ---- */
let dashWatchOpen={};
function toggleWatch(oid,ev){
  if(ev&&(ev.target.closest("button")||ev.target.closest("a")||ev.target.closest("select")||ev.target.closest("input"))) return;
  dashWatchOpen[oid]=!dashWatchOpen[oid];
  render();
}
function watchDetailHTML(o){
  const r=o._r, a=o._a; const ec=effectiveClose(o,r);
  const meta=[
    o.category?["Category",esc(o.category)]:null,
    ["Audit / report",esc(a.name)+(r?" · "+esc(r.title):"")],
    o.timeline?["Resolution timeline",esc(o.timeline)]:null,
    ec?["Expected close",fmtDate(ec)]:null,
    ["Action owner",esc(o.owner||"—")],
    ["Status",statusPill(o.status)]
  ].filter(Boolean);
  const sections=[
    detailSection("Detailed description",o.description),
    detailSection("Impact / risk",o.risk),
    detailSection("Recommendation",o.recommendation),
    detailSection("Management response",o.managementResponse)
  ].join("");
  return `<div class="watch-detail anim-fade-in">
    <div class="watch-detail-meta">${meta.map(([k,v])=>`<div class="watch-meta-item"><span class="watch-meta-label">${k}</span><span class="watch-meta-value">${v}</span></div>`).join("")}</div>
    <div class="obs-detail-sections">${sections||`<div class="hint">No further detail captured for this observation.</div>`}</div>
    <div class="row" style="margin-top:12px;gap:8px">
      <button class="btn sm" onclick="modalAddNote('${a.id}','${r.id}','${o.id}')">${(o.notes||[]).length?"Notes ("+(o.notes||[]).length+")":"+ Add note"}</button>
      <button class="btn sec sm" onclick="go('observation',{audit:'${a.id}',report:'${r.id}',obs:'${o.id}'})">Open full observation →</button>
    </div>
  </div>`;
}
function notesHTML(o){
  const notes=(o.notes||[]).slice().sort((x,y)=>String(y.at||"").localeCompare(String(x.at||"")));
  return `<div class="obs-notes">
    <div class="obs-notes-label">Notes${notes.length?` (${notes.length})`:""}</div>
    ${notes.length?notes.map(n=>`<div class="obs-note"><div class="obs-note-text">${esc(n.text)}</div><div class="obs-note-meta">${esc(n.author||"—")}${n.at?" · "+esc(fmtDateTime(n.at)):""}</div></div>`).join(""):`<div class="hint">No notes yet.</div>`}
  </div>`;
}
function modalAddNote(aid,rid,oid){
  const r=report(audit(aid),rid); const o=r&&r.observations.find(x=>x.id===oid);
  if(!o){ toast("Observation not found."); return; }
  openModal("Add note",`
    <div class="hint" style="margin-bottom:8px">${esc(o.ref?o.ref+" — ":"")}${esc(o.title)}</div>
    <label>Note *</label>
    <textarea id="note_text" style="min-height:120px" placeholder="Progress update, follow-up action, or context…"></textarea>
    ${(o.notes||[]).length?`<div style="margin-top:14px">${notesHTML(o)}</div>`:""}`,
    `<button class="btn sec" onclick="closeModal()">Cancel</button><button class="btn" onclick="saveNote('${aid}','${rid}','${oid}')">Save note</button>`);
  const ta=document.getElementById("note_text"); if(ta) ta.focus();
}
function saveNote(aid,rid,oid){
  const r=report(audit(aid),rid); const o=r&&r.observations.find(x=>x.id===oid);
  if(!o){ toast("Observation not found."); return; }
  const text=val("note_text"); if(!text){ toast("Enter a note first."); return; }
  o.notes=o.notes||[];
  o.notes.push({id:uid(),text,author:(window.AMS_USER&&window.AMS_USER.name)||DB.signOffName||"",at:new Date().toISOString()});
  save();
  if(view==="dashboard") dashWatchOpen[oid]=true;
  closeModal(); render();
}
function kpi(cls,lab,num,sub,icon){
  const icons={
    audit:`<svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.75"><path d="M4 7a2 2 0 0 1 2-2h12a2 2 0 0 1 2 2v11a2 2 0 0 1-2 2H6a2 2 0 0 1-2-2z"/><path d="M8 7V5h8v2"/></svg>`,
    obs:`<svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.75"><path d="M9 5H7a2 2 0 0 0-2 2v10a2 2 0 0 0 2 2h10a2 2 0 0 0 2-2V7a2 2 0 0 0-2-2h-2"/><rect x="9" y="3" width="6" height="4" rx="1"/></svg>`,
    alert:`<svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.75"><path d="M12 9v4"/><path d="M12 17h.01"/><path d="M10.29 3.86 1.82 18a2 2 0 0 0 1.71 3h16.94a2 2 0 0 0 1.71-3L13.71 3.86a2 2 0 0 0-3.42 0z"/></svg>`,
    check:`<svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.75"><path d="M20 6 9 17l-5-5"/></svg>`
  };
  const ic=icons[icon]||icons.audit;
  return `<div class="kpi ${cls}"><div class="kpi-head"><span class="kpi-icon">${ic}</span><div class="lab">${lab}</div></div><div class="num">${num}</div><div class="sub">${sub}</div></div>`;
}
function statusPill(s){
  const k=s||"Open";
  const cls=k==="Closed"?"closed":k==="In Progress"?"progress":"open";
  return `<span class="status-pill ${cls}">${esc(k)}</span>`;
}
function donut(segs,total,label){
  const r=54,C=2*Math.PI*r; let off=0; let idx=0;
  const bg=`<circle cx="70" cy="70" r="${r}" fill="none" stroke="#eef2f7" stroke-width="16"/>`;
  const arcs=segs.filter(s=>s.value>0).map(s=>{ const len=total?s.value/total*C:0; const delay=idx*0.12; idx++;
    const el=`<circle class="donut-seg" cx="70" cy="70" r="${r}" fill="none" stroke="${s.color}" stroke-width="16" stroke-dashoffset="${(-off).toFixed(2)}" transform="rotate(-90 70 70)" style="--seg-len:${len.toFixed(2)};--seg-delay:${delay}s"/>`;
    off+=len; return el; }).join("");
  return `<svg class="donut-chart" viewBox="0 0 140 140" width="148" height="148" style="flex-shrink:0">${bg}${arcs}
    <text class="donut-center-num" x="70" y="66" text-anchor="middle" font-size="30" font-weight="700" fill="#0d5a47">${total}</text>
    <text class="donut-center-lbl" x="70" y="86" text-anchor="middle" font-size="11" fill="#64748b">${label}</text></svg>`;
}
function tlPill(t){
  const map={"Immediate":"immediate","Short-term":"short","Long-term":"long"};
  const cls=map[t];
  if(!cls) return `<span class="timeline-pill empty">—</span>`;
  return `<span class="timeline-pill ${cls}">${esc(t)}</span>`;
}
function statusClass(s){ return s==="Closed"?"s-Closed":s==="In Progress"?"s-InProgress":"s-Open"; }

/* ============================ REMEDIATION TRACKER ============================ */
let trackerFilter={crit:"All",tl:"All",status:"All"};
let trackerMode="actions";
let expandedObs={};
function obsExpandKey(aid,rid,oid){ return aid+"|"+rid+"|"+oid; }
function toggleObsExpand(aid,rid,oid,ev){
  if(ev&&(ev.target.closest("button")||ev.target.closest("select")||ev.target.closest("a")||ev.target.closest("input"))) return;
  const k=obsExpandKey(aid,rid,oid);
  expandedObs[k]=!expandedObs[k];
  render();
}
function trackerTabs(){
  return `<div class="row" style="margin-bottom:14px"><div class="row" style="gap:6px">
    <button class="btn ${trackerMode==="actions"?"":"sec"} sm" onclick="trackerMode='actions';render()">Open Actions</button>
    <button class="btn ${trackerMode==="insights"?"":"sec"} sm" onclick="trackerMode='insights';render()">Insights</button></div></div>`;
}
function trackerSet(k,v){ trackerFilter[k]=v; render(); }
function parseDate(s){ if(!s)return null; const d=new Date(s); return isNaN(d.getTime())?null:d; }
function trackerBucketOf(o){ const d=daysToClose(o,o._r); return d==null?"No date":closeBucket(d); }
function viewTracker(){
  const obs=allObs().filter(obsIsApproved);
  if(!obs.length){
    return `<div class="card"><div class="empty"><div class="big">◷</div>No observations yet. Once you raise observations, every open remediation action shows up here — grouped by expected close, with overdue flags.</div></div>`;
  }
  const isOverdue=o=>isOverdueObs(o,o._r);
  const readyToClose=o=>!!o.ownerRectifiedAt && (o.status||"Open")!=="Closed";
  const openAll=obs.filter(o=>o.status!=="Closed");
  const readyCount=openAll.filter(readyToClose).length;
  const watch=openAll.filter(o=>{ const d=daysToClose(o,o._r); return d!=null && d>=0 && d<=14; }).length;
  const overdue=openAll.filter(isOverdue).length;
  const repeats=openAll.filter(o=>o.isRepeat).length;
  const noClose=openAll.filter(o=>daysToClose(o,o._r)==null).length;

  let items=obs.slice();
  if(trackerFilter.status==="All") items=items.filter(o=>o.status!=="Closed");
  else items=items.filter(o=>(o.status||"Open")===trackerFilter.status);
  if(trackerFilter.crit!=="All") items=items.filter(o=>o.criticality===trackerFilter.crit);
  if(trackerFilter.tl!=="All"){ if(trackerFilter.tl==="Ready to Close") items=items.filter(readyToClose); else items=items.filter(o=>trackerBucketOf(o)===trackerFilter.tl); }

  const CLOSE_GROUPS=["Ready to Close",...CLOSE_BUCKETS,"No date"];
  const groupLabel=g=>g==="No date"?"No expected close date":g==="Ready to Close"?"Ready to close — awaiting verification":g;
  let h=`
  <div class="dash-kpis" style="grid-template-columns:repeat(6,1fr)">
    ${kpi("good","Ready to close",readyCount,"awaiting verification")}
    ${kpi("base","Open actions",openAll.length,"across all audits")}
    ${kpi("warn","Watchlist",watch,"due within 2 weeks")}
    ${kpi("warn","Overdue",overdue,"past expected close")}
    ${kpi("accent","Repeat findings",repeats,"recur from prior audits")}
    ${kpi("base","No close date",noClose,"need an expected close date")}
  </div>
  <div class="card tracker-filters"><div class="filter-row filter-row-right">
    <div class="filter-group"><span class="filter-label">Expected close</span>
      <select class="field-select field-select-sm" onchange="trackerSet('tl',this.value)"><option value="All"${trackerFilter.tl==="All"?" selected":""}>All</option>${CLOSE_GROUPS.map(x=>`<option value="${esc(x)}"${trackerFilter.tl===x?" selected":""}>${esc(groupLabel(x))}</option>`).join("")}</select></div>
    <div class="filter-group"><span class="filter-label">Criticality</span>
      <select class="field-select field-select-sm" onchange="trackerSet('crit',this.value)">${["All",...CRITS].map(x=>`<option value="${esc(x)}"${trackerFilter.crit===x?" selected":""}>${esc(x)}</option>`).join("")}</select></div>
    <div class="filter-group"><span class="filter-label">Status</span>
      <select class="field-select field-select-sm" onchange="trackerSet('status',this.value)">${["All",...STATUSES].map(x=>`<option value="${esc(x)}"${trackerFilter.status===x?" selected":""}>${esc(x)}</option>`).join("")}</select></div>
  </div></div>`;

  const crank=o=>CRITS.indexOf(o.criticality);
  const bcol={"Ready to Close":"#1f8a5b","Overdue":"#b00020","≤ 2 weeks":"#e8590c","2–4 weeks":"#c98a00","1–3 months":"#2c5f8a","> 3 months":"#2e7d32","No date":"#64748b"};
  let any=false;
  CLOSE_GROUPS.forEach(g=>{
    let rows = g==="Ready to Close" ? items.filter(readyToClose) : items.filter(o=>!readyToClose(o) && trackerBucketOf(o)===g);
    if(!rows.length) return;
    any=true;
    rows.sort((a,b)=>{ const da=daysToClose(a,a._r), db=daysToClose(b,b._r); if(da==null&&db==null) return crank(a)-crank(b); if(da==null) return 1; if(db==null) return -1; return (da-db)||(crank(a)-crank(b)); });
    h+=`<div class="card"><div class="row" style="margin-bottom:10px;align-items:center">
      <span class="dot" style="width:11px;height:11px;border-radius:3px;background:${bcol[g]};display:inline-block"></span>
      <div class="seclabel" style="margin:0">${esc(groupLabel(g))}</div>
      <div class="hint">${rows.length} action${rows.length!==1?"s":""}</div></div>
      <table><thead><tr><th>Criticality</th><th>Action / observation</th><th>Audit · Report</th><th>Owner</th><th>Expected close</th><th>Status</th></tr></thead><tbody>
      ${rows.map(o=>{
        const od=isOverdue(o); const ec=effectiveClose(o,o._r);
        const st=o.status||"Open";
        const stCls=st==="Closed"?"closed":st==="In Progress"?"progress":"open";
        return `<tr class="tracker-row" onclick="go('observation',{audit:'${o._a.id}',report:'${o._r.id}',obs:'${o.id}'})" title="Open observation">
          <td><span class="pill c-${ck(o.criticality)}">${o.criticality}</span>${o.isRepeat?`<div style="margin-top:4px"><span class="pill" style="background:#efe3f7;color:#6b3fa0">↻ REPEAT</span></div>`:""}</td>
          <td><b>${esc(o.title)}</b>${o.recommendation?`<div class="hint">${esc(o.recommendation.length>120?o.recommendation.slice(0,119)+"…":o.recommendation)}</div>`:""}</td>
          <td>${esc(o._a.name)}<div class="hint">${esc(o._r.title)}${o._a.area?" · "+esc(o._a.area):""}</div></td>
          <td>${esc(o.owner||"—")}</td>
          <td>${ec?`${fmtDate(ec)}${od?` <span class="pill c-Critical">overdue</span>`:""}`:`<span class="hint">—</span>`}</td>
          <td onclick="event.stopPropagation()"><div class="tracker-status-cell">${statusPill(o.status)}${pendingStatusChange(o.id)?` <span class="pill sop-pending-pill" title="Change to ${esc(pendingStatusChange(o.id).newStatus)} awaiting Head approval">⏳</span>`:""}${o.updateRequestedAt?` <span class="pill sop-pending-pill" title="Update requested from owner">🔔</span>`:""}<span class="tracker-status-actions">${iconBtn(`modalStatusEdit('${o._a.id}','${o._r.id}','${o.id}')`,"✎","Edit status")}${st!=="Closed"?iconBtn(`requestOwnerUpdate('${o._a.id}','${o._r.id}','${o.id}')`,"🔔","Request update from owner"):""}</span></div></td>
        </tr>`;
      }).join("")}
      </tbody></table></div>`;
  });
  if(!any) h+=`<div class="card"><div class="empty">No actions match the current filter.</div></div>`;
  return h;
}
function updateObsStatus(aid,rid,oid,v){
  const a=audit(aid); const r=report(a,rid); if(!r)return;
  const o=r.observations.find(x=>x.id===oid); if(o){ stampClosed(o,v); o.status=v; save(); render(); }
}
/* ---- Status-change approval + owner update requests ---- */
function pendingStatusChange(oid){ return approvals().find(a=>a.kind==="observation_status_change"&&a.obsId===oid&&a.status==="pending"); }
function applyStatusChange(o,v){ stampClosed(o,v); o.status=v; }
function cancelPendingStatusChange(oid){ const u=window.AMS_USER||{}; approvals().forEach(a=>{ if(a.kind==="observation_status_change"&&a.obsId===oid&&a.status==="pending"){ a.status="superseded"; a.decidedBy=u.id||""; a.decidedByName=u.name||""; a.decidedAt=new Date().toISOString(); } }); }
function modalStatusEdit(aid,rid,oid){
  const o=findObs(aid,rid,oid); if(!o)return;
  const pend=pendingStatusChange(oid);
  openModal("Update status",`
    <div class="note" style="margin-bottom:10px"><b>${esc(o.title)}</b> · current: ${statusPill(o.status||"Open")}</div>
    ${pend?`<div class="hint" style="color:#a15c00;margin-bottom:8px">⏳ A change to <b>${esc(pend.newStatus)}</b> is already awaiting Head approval.</div>`:""}
    <label>New status</label><select id="st_new">${STATUSES.map(s=>`<option${(o.status||"Open")===s?" selected":""}>${s}</option>`).join("")}</select>
    <div class="hint" style="margin-top:8px">${isHeadUser()?"As Head of Audit, the change is applied immediately.":"Every status change requires Head of Audit approval."}</div>`,
    `<button class="btn sec" onclick="closeModal()">Cancel</button><button class="btn" onclick="submitStatusEdit('${aid}','${rid}','${oid}')">${isHeadUser()?"Apply":"Request change"}</button>`);
}
function submitStatusEdit(aid,rid,oid){ const v=val("st_new"); closeModal(); requestStatusChange(aid,rid,oid,v); }
function requestStatusChange(aid,rid,oid,v){
  const o=findObs(aid,rid,oid); if(!o)return;
  if(!STATUSES.includes(v)) return;
  if((o.status||"Open")===v) return;
  if(isHeadUser()){ applyStatusChange(o,v); cancelPendingStatusChange(oid); logAudit("obs.status_changed","Status → "+v+": "+o.title,{observationId:oid}); if(o.ownerUserId) notify(o.ownerUserId,"status",o.title+" status is now "+v,"myobs"); save(); render(); return; }
  if(pendingStatusChange(oid)){ toast("A status change for this observation is already awaiting approval."); return; }
  const u=window.AMS_USER||{};
  approvals().push({id:uid(),kind:"observation_status_change",obsId:oid,auditId:aid,reportId:rid,obsTitle:o.title,fromStatus:o.status||"Open",newStatus:v,requestedBy:u.id||"",requestedByName:u.name||"",requestedAt:new Date().toISOString(),status:"pending"});
  logAudit("obs.status_change_requested","Requested status → "+v+": "+o.title,{observationId:oid});
  notifyHeadsApproval(o.title+" (status → "+v+")");
  save(); render(); toast("Status change submitted to the Head of Audit for approval.","success");
}
function approveStatusChange(aid){
  if(!isHeadUser()){ toast("Only the Head of Audit can approve.","error"); return; }
  const ap=approvals().find(x=>x.id===aid); if(!ap||ap.status!=="pending")return;
  const o=findObs(ap.auditId,ap.reportId,ap.obsId);
  const u=window.AMS_USER||{}; ap.status="approved"; ap.decidedBy=u.id||""; ap.decidedByName=u.name||""; ap.decidedAt=new Date().toISOString();
  if(o){ applyStatusChange(o,ap.newStatus); if(o.raisedBy) notify(o.raisedBy,"status_approved","Status change approved: "+o.title,"tracker"); if(o.ownerUserId) notify(o.ownerUserId,"status",o.title+" status is now "+ap.newStatus,"myobs"); }
  logAudit("obs.status_change_approved","Approved status → "+ap.newStatus+": "+(ap.obsTitle||""),{observationId:ap.obsId});
  save(); render();
}
function rejectStatusChange(aid){
  if(!isHeadUser()){ toast("Only the Head of Audit can reject.","error"); return; }
  const ap=approvals().find(x=>x.id===aid); if(!ap||ap.status!=="pending")return;
  const u=window.AMS_USER||{}; ap.status="rejected"; ap.decidedBy=u.id||""; ap.decidedByName=u.name||""; ap.decidedAt=new Date().toISOString();
  const o=findObs(ap.auditId,ap.reportId,ap.obsId); if(o&&o.raisedBy) notify(o.raisedBy,"status_rejected","Status change rejected: "+o.title,"tracker");
  logAudit("obs.status_change_rejected","Rejected status change: "+(ap.obsTitle||""),{observationId:ap.obsId});
  save(); render();
}
function requestOwnerUpdate(aid,rid,oid){
  const o=findObs(aid,rid,oid); if(!o)return;
  if(!o.ownerUserId){ toast("This observation has no assigned action owner — assign one first."); return; }
  const u=window.AMS_USER||{};
  o.updateRequestedAt=new Date().toISOString(); o.updateRequestedBy=u.name||"";
  notify(o.ownerUserId,"update_request","Update requested on: "+o.title,"myobs");
  const dept=deptById(o.departmentId); if(dept&&dept.headEmail) emailNotify([dept.headEmail],"AuditLens — update requested",`The audit team requested an update on "${o.title}". Sign in to AuditLens to respond.`);
  logAudit("obs.update_requested","Requested owner update: "+o.title,{observationId:oid});
  save(); render(); toast("Update requested from the action owner.","success");
}
function exportTracker(){
  const obs=allObs().filter(obsIsApproved).filter(o=>o.status!=="Closed");
  const od=o=>isOverdueObs(o,o._r);
  const crank=o=>CRITS.indexOf(o.criticality);
  let inner=`<h1>Remediation Tracker — Open Actions</h1><div class="meta">${esc(DB.org)} — Internal Audit · ${obs.length} open action(s) · ${obs.filter(o=>o.isRepeat).length} repeat finding(s)</div>`;
  if(!obs.length){ inner+=`<div>No open actions.</div>`; wordDoc("Remediation Tracker "+stamp(),inner); return; }
  [...CLOSE_BUCKETS,"No date"].forEach(g=>{
    let rows=obs.filter(o=>trackerBucketOf(o)===g);
    if(!rows.length)return;
    rows.sort((a,b)=>{ const da=daysToClose(a,a._r), db=daysToClose(b,b._r); if(da==null&&db==null) return crank(a)-crank(b); if(da==null) return 1; if(db==null) return -1; return (da-db)||(crank(a)-crank(b)); });
    inner+=`<h2>${g==="No date"?"No expected close date":g} (${rows.length})</h2>
      <table><tr><th>Criticality</th><th>Action / observation</th><th>Audit · Report</th><th>Owner</th><th>Expected close</th><th>Age</th><th>Repeat</th><th>Status</th></tr>
      ${rows.map(o=>{ const ec=effectiveClose(o,o._r); const age=obsAge(o,o._r); return `<tr><td><span class="pill ${ck(o.criticality)}">${o.criticality}</span></td><td>${esc(o.title)}</td><td>${esc(o._a.name)} · ${esc(o._r.title)}</td><td>${esc(o.owner||"—")}</td><td>${ec?fmtDate(ec):"—"}${od(o)?" (overdue)":""}</td><td>${age!=null?age+"d":"—"}</td><td>${o.isRepeat?"Yes"+(o.repeatOf?" ("+esc(o.repeatOf)+")":""):"—"}</td><td>${esc(o.status||"Open")}</td></tr>`; }).join("")}</table>`;
  });
  wordDoc("Remediation Tracker "+stamp(),inner);
}

/* ============================ INSIGHTS ============================ */
function viewInsights(){
  const obs=allObs().filter(obsIsApproved);
  if(!obs.length) return `<div class="card"><div class="empty"><div class="big">◎</div>No observations yet. Once you log observations, this tab analyses recurring root causes and plots a risk heat map.</div></div>`;
  const themeCount={}; const themeAreas={};
  obs.forEach(o=>{ rcThemes(o.rootCause).forEach(t=>{ themeCount[t]=(themeCount[t]||0)+1; (themeAreas[t]=themeAreas[t]||new Set()).add(o._a.area||o._a.name); }); });
  const themeRows=Object.entries(themeCount).sort((a,b)=>b[1]-a[1]);
  const maxTheme=Math.max(1,...themeRows.map(r=>r[1]));
  const clusters=clusterRootCauses(obs);
  const areas={}; obs.forEach(o=>{ const k=o._a.area||o._a.name; (areas[k]=areas[k]||zc())[o.criticality]++; });
  const areaRows=Object.entries(areas).map(([k,v])=>[k,v,CRITS.reduce((s,c)=>s+v[c],0)]).sort((a,b)=>b[2]-a[2]).slice(0,12);
  const maxCell=Math.max(1,...areaRows.flatMap(([,v])=>CRITS.map(c=>v[c])));
  const colLab={Critical:"Critical",High:"High",Moderate:"Moderate",Low:"Low","Process Improvement":"Proc. Improve"};
  return `
  <div class="card"><div class="seclabel">Recurring root-cause themes</div>
    <p class="hint" style="margin-top:-6px">How often each underlying cause appears across observations (a finding can map to more than one theme). The longest bars are your systemic focus areas.</p>
    ${themeRows.map(([t,v])=>`<div class="rcrow"><div class="nm" title="${[...(themeAreas[t]||[])].map(esc).join(", ")}">${esc(t)}</div><div class="track"><div class="fill" style="width:${v/maxTheme*100}%"></div></div><div class="vv">${v}</div></div>`).join("")}
  </div>
  <div class="card"><div class="seclabel">Recurring specific root causes</div>
    ${clusters.length? clusters.map(cl=>`
      <div class="obs-block" style="padding:11px 13px;margin-bottom:10px;background:#e9f8f2;border-color:#c6e9df">
        <div class="row" style="align-items:flex-start"><b style="flex:1">${esc(cl.rep)}</b><span class="pill" style="background:#eef2f7;color:#334155">×${cl.items.length}</span></div>
        <div class="hint" style="margin-top:5px">Recurs in: ${cl.items.map(i=>esc(i._a.name)+(i._a.area?" ("+esc(i._a.area)+")":"")).filter((v,ix,arr)=>arr.indexOf(v)===ix).join(" · ")}</div>
      </div>`).join("")
      : `<div class="hint">No root cause appears in two or more observations yet. As findings accrue, recurring causes cluster here.</div>`}
  </div>
  <div class="card"><div class="seclabel">Risk heat map — process / department × criticality</div>
    <p class="hint" style="margin-top:-6px">Cell colour = severity; intensity = number of observations. Dense red rows are the areas needing most focus.</p>
    <table class="hm"><thead><tr><th class="axis">Process / Department</th>${CRITS.map(c=>`<th>${colLab[c]}</th>`).join("")}<th>Total</th></tr></thead><tbody>
      ${areaRows.map(([k,v,tot])=>`<tr><td class="axis">${esc(k)}</td>${CRITS.map(c=>{ const n=v[c]; const bg=n?hx2rgba(CRIT_HEX[c],0.16+0.8*(n/maxCell)):"#f7f9fb"; return `<td class="cell" style="background:${bg};color:${n&&(n/maxCell)>0.55?'#fff':'#1c2733'}">${n||""}</td>`; }).join("")}<td class="cell" style="background:#f1f5f9"><b>${tot}</b></td></tr>`).join("")}
    </tbody></table>
  </div>`;
}
function clusterRootCauses(obs){
  const items=obs.filter(o=>(o.rootCause||"").trim().length>8);
  const used=new Array(items.length).fill(false); const clusters=[];
  for(let i=0;i<items.length;i++){
    if(used[i])continue; const group=[items[i]]; used[i]=true;
    for(let j=i+1;j<items.length;j++){ if(used[j])continue;
      const s=repSim(items[i].rootCause,items[j].rootCause);
      if((s.shared>=2 && s.score>=0.34) || s.dice>=0.55){ group.push(items[j]); used[j]=true; } }
    if(group.length>=2) clusters.push({rep:items[i].rootCause.length>170?items[i].rootCause.slice(0,169)+"…":items[i].rootCause, items:group});
  }
  return clusters.sort((a,b)=>b.items.length-a.items.length).slice(0,8);
}
function exportInsights(){
  const obs=allObs().filter(obsIsApproved); if(!obs.length){ toast("No observations to analyse."); return; }
  const themeCount={}; obs.forEach(o=>rcThemes(o.rootCause).forEach(t=>themeCount[t]=(themeCount[t]||0)+1));
  const themeRows=Object.entries(themeCount).sort((a,b)=>b[1]-a[1]);
  const areas={}; obs.forEach(o=>{ const k=o._a.area||o._a.name; (areas[k]=areas[k]||zc())[o.criticality]++; });
  const clusters=clusterRootCauses(obs);
  let inner=`<h1>Audit Insights</h1><div class="meta">${esc(DB.org)} — Internal Audit · thematic analysis across ${obs.length} observation(s)</div>
    <h2>Recurring Root-Cause Themes</h2>
    <table><tr><th>Theme</th><th>Count</th></tr>${themeRows.map(([t,v])=>`<tr><td>${esc(t)}</td><td>${v}</td></tr>`).join("")}</table>
    ${clusters.length?`<h2>Recurring Specific Root Causes</h2><table><tr><th>Root cause</th><th>Occurrences</th></tr>${clusters.map(cl=>`<tr><td>${esc(cl.rep)}</td><td>${cl.items.length}</td></tr>`).join("")}</table>`:""}
    <h2>Risk Heat Map — Process/Department × Criticality</h2>
    <table><tr><th>Area</th>${CRITS.map(c=>`<th>${c}</th>`).join("")}<th>Total</th></tr>
    ${Object.entries(areas).sort((a,b)=>CRITS.reduce((s,c)=>s+b[1][c],0)-CRITS.reduce((s,c)=>s+a[1][c],0)).map(([k,v])=>{ const tot=CRITS.reduce((s,c)=>s+v[c],0); return `<tr><td>${esc(k)}</td>${CRITS.map(c=>`<td style="text-align:center">${v[c]||""}</td>`).join("")}<td><b>${tot}</b></td></tr>`; }).join("")}
    </table>`;
  wordDoc("Audit Insights "+stamp(),inner);
}

/* ============================ AUDIT RISK ASSESSMENT / PLAN ============================ */
let curRaUnit=null;
function planYearsList(){
  const set=new Set();
  (DB.planYears||[]).forEach(y=>set.add(String(y)));
  auditUniverse().forEach(e=>raYearsIn(e.plannedPeriod).forEach(y=>set.add(String(y))));
  if(DB.planYear) set.add(String(DB.planYear));
  const arr=[...set].filter(Boolean);
  if(!arr.length) arr.push(String(planYear()));
  return arr.sort((a,b)=>+a-+b);
}
function raPlanYearOptions(sel){ return planYearsList().map(y=>`<option value="${esc(y)}"${String(sel)===y?" selected":""}>${esc(y)}</option>`).join(""); }
function planYearHasData(y){ return auditUniverse().some(e=>raYearsIn(e.plannedPeriod).includes(+y)) || (DB.planYears||[]).map(String).includes(String(y)); }
function modalNewAuditPlan(){
  if(!requireHead())return;
  const cur=(new Date()).getFullYear();
  const U=auditUniverse().slice().sort((a,b)=>raComposite(b.factors)-raComposite(a.factors));
  openModal("New annual audit plan",`
    <label>Plan year *</label>
    <input type="number" id="np_year" min="2000" max="2100" value="${cur}" placeholder="e.g. ${cur}">
    <div id="np_err" style="margin-top:8px"></div>
    <div class="seclabel" style="margin:16px 0 6px">Which units go into this plan?</div>
    <label class="filter-check" style="display:flex;align-items:center;gap:8px;font-weight:600;margin-bottom:8px"><input type="checkbox" id="np_all" checked onchange="npToggleAll(this)" style="width:auto"> Include all ${U.length} unit(s)</label>
    <div class="np-unit-list">
      ${U.map(e=>{ const band=e.ratingOverride||raBand(raComposite(e.factors)); return `<label class="filter-check np-unit-row"><input type="checkbox" class="np_unit" value="${e.id}" checked onchange="npSyncAll()" style="width:auto"><span class="np-unit-name">${esc(e.name)}</span>${e.category?`<span class="hint np-unit-cat">${esc(e.category)}</span>`:""}<span class="pill" style="background:${hx2rgba(RA_HEX[band],.16)};color:${RA_HEX[band]}">${band}</span></label>`; }).join("")}
    </div>
    <div class="hint" style="margin-top:8px">Checked units are scheduled into the plan year (their timing rolls to that year — edit a unit to set quarters). Unchecked units are excluded from this year's plan.</div>`,
    `<button class="btn sec" onclick="closeModal()">Cancel</button><button class="btn" onclick="createAuditPlan()">Create plan</button>`);
}
function npToggleAll(cb){ document.querySelectorAll(".np_unit").forEach(x=>{ x.checked=cb.checked; }); }
function npSyncAll(){ const all=document.getElementById("np_all"); if(!all)return; const boxes=Array.from(document.querySelectorAll(".np_unit")); all.checked=boxes.length>0 && boxes.every(x=>x.checked); }
function createAuditPlan(){
  const y=val("np_year"); const errEl=document.getElementById("np_err");
  if(!/^20\d{2}$/.test(y)){ if(errEl) errEl.innerHTML=`<div class="hint" style="color:var(--crit)">Enter a valid year, e.g. ${(new Date()).getFullYear()}.</div>`; return; }
  if(planYearHasData(y)){ if(!confirm(`A plan already exists for ${y}. Switch to it and re-apply the selected units?`)) return; }
  const checked=new Set(Array.from(document.querySelectorAll(".np_unit:checked")).map(x=>x.value));
  if(!checked.size){ if(errEl) errEl.innerHTML=`<div class="hint" style="color:var(--crit)">Select at least one unit for the plan.</div>`; return; }
  auditUniverse().forEach(e=>{
    if(checked.has(e.id)){ e.includeInPlan=true; if((e.plannedPeriod||"").trim()) e.plannedPeriod=e.plannedPeriod.replace(/20\d{2}/g,y); }
    else { e.includeInPlan=false; }
  });
  DB.planYears=DB.planYears||[]; if(!DB.planYears.map(String).includes(y)) DB.planYears.push(y);
  DB.planYear=y; logAudit("plan.year_created","Opened annual plan for "+y+" ("+checked.size+" unit(s))",{year:y}); save(); closeModal(); render();
}
function viewAuditRA(){
  const U=auditUniverse();
  if(!U.length){
    return `<div class="card"><div class="empty"><div class="big">◈</div>No auditable units yet.<br><br>
      <button class="btn dark ai-generate-btn" onclick="modalRAPrompt()">Generate audit universe</button> &nbsp; <button class="btn" onclick="modalRA()">+ Add auditable unit</button></div></div>`;
  }
  rolloverPlan();
  const py=+planYear();
  const en=U.map(e=>{ const score=raComposite(e.factors); const band=e.ratingOverride||raBand(score); const due=raDue(e,band); return {...e,score,band,due,incl:raInPlan(e,band,due),freq:e.frequencyOverride||raFreqLabel(band)}; }).sort((a,b)=>b.score-a.score);
  const counts={Critical:0,High:0,Medium:0,Low:0}; en.forEach(e=>counts[e.band]++);
  const dueN=en.filter(e=>e.due).length; const planned=en.filter(e=>e.incl);
  const totalOcc=planned.reduce((s,e)=>s+unitOccTotal(e),0);
  const doneOcc=planned.reduce((s,e)=>s+unitOccDone(e),0);
  const pctPlan=totalOcc?Math.round(doneOcc/totalOcc*100):0;
  let h=`<div class="ra-toolbar">
    <div class="filter-group"><span class="filter-label">Plan year</span>
      <select class="field-select field-select-sm" onchange="DB.planYear=this.value;save();render();">${raPlanYearOptions(planYear())}</select></div>
  </div>
  <div class="dash-kpis" style="grid-template-columns:repeat(5,1fr)">
    ${kpi("warn","High / Critical",counts.High+counts.Critical,"units by risk rating")}
    ${kpi("base","Auditable units",U.length,"in the universe")}
    ${kpi("accent","Due in "+py,dueN,"by frequency cycle")}
    ${kpi("base","In "+py+" plan",planned.length,"selected for the year")}
    ${kpi("good","Plan delivered",pctPlan+"%",doneOcc+" of "+totalOcc+" reviews done")}
  </div>
  <div class="card"><div class="row" style="align-items:center;gap:10px;margin-bottom:2px"><div class="seclabel" style="margin:0">Risk-ranked audit universe</div><div class="spacer"></div>${isStaff()?"":`<button class="btn sm" onclick="modalRA()">+ Add unit</button>`}</div>
    <table class="ra-universe-table" style="margin-top:6px"><thead><tr><th>Auditable unit</th><th>Category</th><th>Risk score</th><th>Rating</th><th>Last audited</th><th>Frequency</th><th>Due</th><th></th></tr></thead><tbody>
    ${en.map(e=>`<tr>
      <td><b>${esc(e.name)}</b>${e.owner?`<div class="hint">${esc(e.owner)}</div>`:""}</td>
      <td>${esc(e.category||"—")}</td>
      <td style="text-align:center">${e.score.toFixed(2)}</td>
      <td><span class="pill" style="background:${hx2rgba(RA_HEX[e.band],.16)};color:${RA_HEX[e.band]}">${e.band}</span></td>
      <td style="text-align:center">${esc(e.lastAudited||"—")}</td>
      <td>${esc(e.freq)}</td>
      <td style="text-align:center">${raDueDisplay(e,e.band,e.due)}</td>
      <td class="ra-actions-cell">${iconBtn(`modalRA('${e.id}')`,"✎","Edit")}${delBtn(`delRA('${e.id}')`)}</td>
    </tr>`).join("")}
    </tbody></table>
    <div class="hint" style="margin-top:8px">Risk score = weighted average of factors (1–5). Frequency: Critical/High = annual · Medium = 2 yrs · Low = 3 yrs. “Due” = last audited + cycle ≤ plan year (or never audited).</div>
  </div>
  <div class="card"><div class="row" style="align-items:center;gap:10px"><div class="seclabel" style="margin:0">Annual Audit Plan — ${esc(planYear())}</div><div class="spacer"></div><span class="hint">${planned.length} engagement(s) · ${doneOcc}/${totalOcc} quarter-reviews done (${pctPlan}%)</span>${isStaff()?"":`<button class="btn sm dark ai-generate-btn" onclick="modalAnnualPlanPrompt()">${planned.some(e=>(e.plannedPeriod||"").trim()||(e.rationale||"").trim())?"Regenerate":"Generate"} plan (AI)</button>`}</div>
    ${planned.length?`<div class="hint" style="margin:2px 0 8px">Click a row to open the full engagement — details, linked audits and status.</div><table class="ra-plan-table" style="margin-top:6px"><thead><tr><th class="ra-plan-num-col">#</th><th>Auditable unit</th><th class="ra-rating-col">Rating</th><th class="ra-timing-col">Timing</th><th>Status</th><th class="ra-link-col">Linked audit</th></tr></thead><tbody>
      ${planned.map((e,i)=>`<tr class="ra-plan-row" onclick="raPlanOpenUnit('${e.id}',event)" title="Open engagement">
        <td class="ra-plan-num-col">${i+1}</td>
        <td><b>${esc(e.name)}</b><div class="hint">${esc(e.freq)}${e.carryOverFrom?` · <span class="ra-carry">carried over from ${esc(String(e.carryOverFrom))}</span>`:""}</div></td>
        <td class="ra-rating-col"><span class="pill" style="background:${hx2rgba(RA_HEX[e.band],.16)};color:${RA_HEX[e.band]}">${e.band}</span></td>
        <td class="ra-timing-col">${e.plannedPeriod?esc(e.plannedPeriod):`<span class="hint">—</span>`}</td>
        <td>${engStatusSummary(e)}</td>
        <td class="ra-link-col">${auditLinksCell(e)}</td>
      </tr>`).join("")}
    </tbody></table>`:`<div class="hint" style="margin:8px 0">No units in plan for this year.</div>`}
  </div>`;
  return h;
}
function raLinkIds(e){ return e.linkedAuditIds || (e.linkedAuditId?[e.linkedAuditId]:[]); }
function auditLinksCell(e){
  const ids=raLinkIds(e);
  const linked=ids.map(id=>DB.audits.find(a=>a.id===id)).filter(Boolean);
  const avail=DB.audits.filter(a=>!ids.includes(a.id));
  return `<div class="ra-linkbox">${linked.map(a=>`<span class="tag ra-link-tag" title="Open audit" onclick="event.stopPropagation();go('audit',{audit:'${a.id}'})">${esc(a.name)} <span class="tag-unlink" title="Unlink" onclick="event.stopPropagation();raLinkRemove('${e.id}','${a.id}')">${ICON_TRASH}</span></span>`).join("")}${avail.length?`<div class="ra-link-search"><input class="ra-link-input" placeholder="${linked.length?"+ link another…":"+ link audit…"}" oninput="raLinkFilter(this)" onfocus="raLinkFilter(this)" onclick="event.stopPropagation()"><div class="ra-link-menu">${avail.map(a=>`<div class="ra-link-opt" data-name="${esc(a.name.toLowerCase())}" onmousedown="event.preventDefault()" onclick="event.stopPropagation();raLinkAdd('${e.id}','${a.id}')">${esc(a.name)}</div>`).join("")}</div></div>`:(linked.length?"":`<span class="hint">no audits yet</span>`)}</div>`;
}
function raLinkFilter(input){
  const q=input.value.toLowerCase().trim();
  const menu=input.parentNode.querySelector(".ra-link-menu"); if(!menu)return;
  menu.querySelectorAll(".ra-link-empty").forEach(x=>x.remove());
  let n=0; menu.querySelectorAll(".ra-link-opt").forEach(o=>{ const dn=o.getAttribute("data-name")||""; const show=(!q||dn.indexOf(q)>=0); o.style.display=show?"":"none"; if(show)n++; });
  if(!n){ const d=document.createElement("div"); d.className="ra-link-opt ra-link-empty"; d.style.color="#94a3b8"; d.textContent="No matches"; menu.appendChild(d); }
}
function raLinkAdd(id,aid){ if(!aid)return; const e=auditUniverse().find(x=>x.id===id); if(!e)return; const ids=raLinkIds(e).slice(); if(!ids.includes(aid))ids.push(aid); e.linkedAuditIds=ids; delete e.linkedAuditId; save(); render(); }
function raLinkRemove(id,aid){ const e=auditUniverse().find(x=>x.id===id); if(!e)return; e.linkedAuditIds=raLinkIds(e).filter(x=>x!==aid); delete e.linkedAuditId; save(); render(); }
function raToggle(id){ const e=auditUniverse().find(x=>x.id===id); if(!e)return; const score=raComposite(e.factors); const band=e.ratingOverride||raBand(score); const due=raDue(e,band); e.includeInPlan=!raInPlan(e,band,due); save(); render(); }
function raSetPeriod(id,v){ const e=auditUniverse().find(x=>x.id===id); if(e){ e.plannedPeriod=v; save(); render(); } }
function raEngSet(id,v){ const e=auditUniverse().find(x=>x.id===id); if(e){ e.engStatus=v; save(); render(); } }
function parseQuarters(s){
  s=String(s||""); const out=[];
  s=s.replace(/Q\s*([1-4])\s*[–-]\s*Q\s*([1-4])(\s*\d{4})?/gi,(m,a,b,y)=>{ const yr=(y||"").trim(); for(let i=+a;i<=+b;i++) out.push("Q"+i+(yr?" "+yr:"")); return " "; });
  const re=/Q\s*([1-4])(\s*\d{4})?/gi; let m; while((m=re.exec(s))){ const yr=(m[2]||"").trim(); out.push("Q"+m[1]+(yr?" "+yr:"")); }
  const seen={}, res=[]; out.forEach(q=>{ q=q.replace(/\s+/g," ").trim(); if(!seen[q]){seen[q]=1;res.push(q);} }); return res;
}
function unitOcc(e){ const qs=parseQuarters(e.plannedPeriod); const d={}; (e.occDone||[]).forEach(q=>d[q]=1); return qs.map(q=>({q,done:!!d[q]})); }
function unitOccTotal(e){ return Math.max(1,parseQuarters(e.plannedPeriod).length); }
function unitOccDone(e){ const occ=unitOcc(e); return occ.length>1? occ.filter(o=>o.done).length : (e.engStatus==="Completed"?1:0); }
function engStatusText(e){ const occ=unitOcc(e); if(occ.length>1){ const d=occ.filter(o=>o.done).length; return d>=occ.length?"Completed (all quarters)":d>0?d+"/"+occ.length+" quarters done":"Not started"; } return e.engStatus||"Not started"; }
function engStatusLabel(e){ if(engIsComplete(e))return "Completed"; if(pendingCompletion(e.id))return "Pending approval"; return e.engStatus||"Not started"; }
function engStatusSummary(e){
  if(pendingCompletion(e.id)) return `<span class="pill ra-pending-pill">⏳ Pending approval</span>`;
  const total=unitOccTotal(e); const done=unitOccDone(e);
  const complete=engIsComplete(e);
  return `<span class="pill ra-quarter-pill${complete?" done":""}">${done}/${total} quarter${total!==1?"s":""}</span>`;
}
let raPlanOpen={};
function raPlanOpenUnit(id,ev){
  if(ev&&(ev.target.closest("button")||ev.target.closest("a")||ev.target.closest("select")||ev.target.closest("input")||ev.target.closest(".ra-linkbox")||ev.target.closest(".tag"))) return;
  go("raunit",{unit:id});
}
function renderRaUnit(C,T,A){
  const e=auditUniverse().find(x=>x.id===curRaUnit);
  if(!e){ go("auditra"); return; }
  const score=raComposite(e.factors); const band=e.ratingOverride||raBand(score);
  T.textContent=pageTitleFor("auditra");
  setTopBack(backBtn("go('auditra')"));
  A.innerHTML=`<button class="btn sec sm" onclick="modalRA('${e.id}')">Edit unit &amp; timing</button>`;
  C.innerHTML=`<div class="obs-detail-page anim-fade-in">
    <header class="obs-detail-hero">
      <div class="obs-detail-badges">
        <span class="pill" style="background:${hx2rgba(RA_HEX[band],.16)};color:${RA_HEX[band]}">${band}</span>
        ${engStatusSummary(e)}
        ${e.plannedPeriod?`<span class="tag">${esc(e.plannedPeriod)}</span>`:""}
        ${e.carryOverFrom?`<span class="pill ra-pending-pill">carried over from ${esc(String(e.carryOverFrom))}</span>`:""}
      </div>
      <h2 class="obs-detail-title">${esc(e.name)}</h2>
      <p class="hint" style="margin:8px 0 0">${esc(e.category||"Auditable unit")} · Annual Audit Plan ${esc(planYear())}</p>
    </header>
    <div class="ra-unit-body">${raPlanDetailHTML(e)}</div>
  </div>`;
}
function raPlanDetailHTML(e){
  const score=raComposite(e.factors); const band=e.ratingOverride||raBand(score);
  const factorRows=RA_FACTORS.map(([k,lab,w])=>`<div class="ra-factor"><span class="ra-factor-lbl">${esc(lab)} <span class="hint">(${Math.round(w*100)}%)</span></span><span class="ra-factor-val">${(+(e.factors&&e.factors[k])||3)}/5</span></div>`).join("");
  const ids=raLinkIds(e); const linked=ids.map(id=>DB.audits.find(a=>a.id===id)).filter(Boolean);
  return `<div class="ra-plan-detail anim-fade-in">
    <div class="watch-detail-meta">
      <div class="watch-meta-item"><span class="watch-meta-label">Category</span><span class="watch-meta-value">${esc(e.category||"—")}</span></div>
      <div class="watch-meta-item"><span class="watch-meta-label">Owner</span><span class="watch-meta-value">${esc(e.owner||"—")}</span></div>
      <div class="watch-meta-item"><span class="watch-meta-label">Risk score</span><span class="watch-meta-value">${score.toFixed(2)} · ${band}</span></div>
      <div class="watch-meta-item"><span class="watch-meta-label">Frequency</span><span class="watch-meta-value">${esc(e.frequencyOverride||raFreqLabel(band))}</span></div>
      <div class="watch-meta-item"><span class="watch-meta-label">Planned timing</span><span class="watch-meta-value">${esc(e.plannedPeriod||"—")}${e.carryOverFrom?` <span class="hint">(carried over from ${esc(String(e.carryOverFrom))})</span>`:""}</span></div>
      <div class="watch-meta-item"><span class="watch-meta-label">Last audited</span><span class="watch-meta-value">${esc(e.lastAudited||"—")}</span></div>
    </div>
    <div class="ra-factor-grid">${factorRows}</div>
    ${e.rationale?`<div class="obs-detail-sections"><section class="obs-detail-section"><h4 class="obs-detail-label">Rationale</h4><div class="obs-detail-content">${esc(e.rationale)}</div></section></div>`:""}
    <div class="ra-detail-linked"><span class="watch-meta-label">Linked audits</span> ${auditLinksCell(e)}</div>
    ${raStatusSection(e)}
    <div class="row" style="margin-top:12px;gap:8px"><button class="btn ghost sm" onclick="modalRA('${e.id}')">Edit unit &amp; timing</button></div>
  </div>`;
}
function raStatusSection(e){
  const pend=pendingCompletion(e.id);
  const complete=engIsComplete(e);
  let body;
  if(complete){
    body=`<span class="ra-status-text done">✓ Completed</span> <button class="btn ghost sm" onclick="raReopen('${e.id}')">Reopen</button>`;
  } else if(pend){
    const who=esc(pend.requestedByName||"a staff member"); const when=pend.requestedAt?esc(fmtDateTime(pend.requestedAt)):"";
    body=`<span class="pill ra-pending-pill">⏳ Pending Head of Audit approval</span> <span class="hint">requested by ${who}${when?" · "+when:""}</span>`+
      (isHeadUser()?` <button class="btn sm" onclick="approveCompletion('${pend.id}')">Approve</button> <button class="btn ghost sm danger" onclick="rejectCompletion('${pend.id}')">Reject</button>`:"");
  } else {
    body=`<span class="ra-status-text">${esc(engStatusLabel(e))}</span>`+
      (e.engStatus==="In progress"?"":` <button class="btn ghost sm" onclick="raSetInProgress('${e.id}')">Mark in progress</button>`)+
      ` <button class="btn sm" onclick="raRequestComplete('${e.id}')">${isHeadUser()?"Mark completed":"Request completion"}</button>`;
  }
  return `<div class="ra-status-section"><div class="watch-meta-label" style="margin-bottom:6px">Status</div><div class="row" style="gap:8px;align-items:center;flex-wrap:wrap">${body}</div>${!isHeadUser()&&!complete&&!pend?`<div class="hint" style="margin-top:6px">Marking an engagement complete needs Head of Audit approval.</div>`:""}</div>`;
}
function raSetInProgress(id){ const e=auditUniverse().find(x=>x.id===id); if(!e)return; e.engStatus="In progress"; save(); render(); }
function raReopen(id){ const e=auditUniverse().find(x=>x.id===id); if(!e)return; e.engStatus="In progress"; e.occDone=[]; save(); render(); }
function raMarkComplete(e){ e.engStatus="Completed"; e.occDone=parseQuarters(e.plannedPeriod).slice(); save(); render(); }
function raRequestComplete(id){
  const e=auditUniverse().find(x=>x.id===id); if(!e)return;
  if(isHeadUser()){ raMarkComplete(e); logAudit("plan.completed","Marked engagement complete: "+e.name,{unitId:id}); return; }
  if(pendingCompletion(id)){ toast("A completion approval is already pending for this engagement."); return; }
  const u=window.AMS_USER||{};
  approvals().push({id:uid(),kind:"engagement_completion",unitId:id,unitName:e.name,requestedBy:u.id||"",requestedByName:u.name||"",requestedAt:new Date().toISOString(),status:"pending"});
  logAudit("plan.completion_requested","Requested completion approval: "+e.name,{unitId:id});
  save(); render(); toast("Sent to the Head of Audit for approval.","success");
}
function approveCompletion(aid){
  if(!isHeadUser()){ toast("Only the Head of Audit can approve.","error"); return; }
  const a=approvals().find(x=>x.id===aid); if(!a||a.status!=="pending")return;
  const e=auditUniverse().find(x=>x.id===a.unitId);
  const u=window.AMS_USER||{}; a.status="approved"; a.decidedBy=u.id||""; a.decidedByName=u.name||""; a.decidedAt=new Date().toISOString();
  if(e){ e.engStatus="Completed"; e.occDone=parseQuarters(e.plannedPeriod).slice(); }
  logAudit("plan.completion_approved","Approved completion: "+(a.unitName||""),{unitId:a.unitId});
  save(); render();
}
function rejectCompletion(aid){
  if(!isHeadUser()){ toast("Only the Head of Audit can reject.","error"); return; }
  const a=approvals().find(x=>x.id===aid); if(!a||a.status!=="pending")return;
  const u=window.AMS_USER||{}; a.status="rejected"; a.decidedBy=u.id||""; a.decidedByName=u.name||""; a.decidedAt=new Date().toISOString();
  logAudit("plan.completion_rejected","Rejected completion: "+(a.unitName||""),{unitId:a.unitId});
  save(); render();
}
function raOccToggle(id,q){ const e=auditUniverse().find(x=>x.id===id); if(!e)return; e.occDone=e.occDone||[]; e.occDone=e.occDone.includes(q)?e.occDone.filter(x=>x!==q):e.occDone.concat(q); save(); render(); }
/* ---- Head of Audit approvals ---- */
function updateApprovalsBadge(){
  const btn=document.querySelector('#nav button[data-view="approvals"]'); if(!btn) return;
  let b=btn.querySelector(".nav-badge");
  const n=isHeadUser()?pendingApprovalCount():0;
  if(n>0){ if(!b){ b=document.createElement("span"); b.className="nav-badge"; btn.appendChild(b); } b.textContent=String(n); }
  else if(b){ b.remove(); }
}
/* ---- Notification center (topbar bell) ---- */
function unreadNotifCount(){ return myNotifications().filter(n=>!n.read).length; }
function renderNotifBell(){
  const el=document.getElementById("notifBell"); if(!el) return;
  if(!window.AMS_USER || view==="auditra" || view==="raunit"){ el.innerHTML=""; return; }
  const open=el.querySelector(".notif-panel") && el.querySelector(".notif-panel").style.display==="block";
  const n=unreadNotifCount();
  el.innerHTML=`<button class="notif-bell-btn${n>0?" has-unread":""}" type="button" onclick="toggleNotifPanel(event)" title="Notifications" aria-label="Notifications"><svg viewBox="0 0 24 24" width="20" height="20" fill="currentColor" aria-hidden="true"><path d="M12 2a2 2 0 0 0-2 2v.35A6 6 0 0 0 6 10v3l-1.3 2.6A1 1 0 0 0 5.6 17h12.8a1 1 0 0 0 .9-1.45L18 13v-3a6 6 0 0 0-4-5.65V4a2 2 0 0 0-2-2Z"/><path d="M9.9 18a2.1 2.1 0 0 0 4.2 0Z"/></svg>${n>0?`<span class="notif-badge">${n>99?"99+":n}</span>`:""}</button>
    <div class="notif-panel" id="notifPanel" style="display:${open?"block":"none"}">${notifPanelHTML()}</div>`;
}
function notifPanelHTML(){
  const list=myNotifications().slice(0,30);
  return `<div class="notif-head"><b>Notifications</b>${list.some(n=>!n.read)?`<button class="btn ghost sm" type="button" onclick="markAllNotifsRead(event)">Mark all read</button>`:""}</div>
    <div class="notif-list">${list.length?list.map(n=>`<div class="notif-item${n.read?"":" unread"}" onclick="openNotif('${n.id}')"><div class="notif-text">${esc(n.text)}</div><div class="notif-time">${esc(fmtDateTime(n.at))}</div></div>`).join(""):`<div class="notif-empty hint">No notifications yet.</div>`}</div>`;
}
function toggleNotifPanel(ev){ if(ev){ ev.stopPropagation(); } const p=document.getElementById("notifPanel"); if(p) p.style.display=p.style.display==="none"?"block":"none"; }
function closeNotifPanel(){ const p=document.getElementById("notifPanel"); if(p) p.style.display="none"; }
function markAllNotifsRead(ev){ if(ev) ev.stopPropagation(); const me=window.AMS_USER; if(!me) return; let ch=false; notifications().forEach(n=>{ if(n.userId===me.id && !n.read){ n.read=true; ch=true; } }); if(ch){ save(); render(); } }
function openNotif(id){
  const n=notifications().find(x=>x.id===id); if(!n) return;
  if(!n.read){ n.read=true; save(); }
  closeNotifPanel();
  const nav={observation:"audits",tracker:"tracker"}[n.link]||n.link;
  if(nav && canAccessView(nav)){ go(nav); } else { render(); }
}
function approvalKindLabel(k){ return k==="observation_raise"?"New observation":k==="engagement_completion"?"Plan completion":k==="observation_status_change"?"Status change":k==="observation_update_request"?"Update request":(k||"—"); }
function approvalItemTitle(a){ if(a.kind==="engagement_completion"){ const e=auditUniverse().find(x=>x.id===a.unitId); return e?e.name:(a.unitName||"(removed unit)"); } return a.obsTitle||a.unitName||"(item)"; }
function approveAny(aid){ const a=approvals().find(x=>x.id===aid); if(!a)return; if(a.kind==="engagement_completion") return approveCompletion(aid); if(a.kind==="observation_raise") return approveObservation(aid); if(a.kind==="observation_status_change") return approveStatusChange(aid); }
function rejectAny(aid){ const a=approvals().find(x=>x.id===aid); if(!a)return; if(a.kind==="engagement_completion") return rejectCompletion(aid); if(a.kind==="observation_raise") return rejectObservation(aid); if(a.kind==="observation_status_change") return rejectStatusChange(aid); }
function viewApprovals(){
  if(!isHeadUser()) return `<div class="card"><div class="empty">Approvals are only available to the Head of Audit.</div></div>`;
  const all=approvals().slice().sort((a,b)=>String(b.requestedAt||"").localeCompare(String(a.requestedAt||"")));
  const pend=all.filter(a=>a.status==="pending");
  const decided=all.filter(a=>a.status!=="pending").slice(0,25);
  let h=`<div class="dash-kpis" style="grid-template-columns:repeat(3,1fr)">
    ${kpi("warn","Pending",pend.length,"awaiting your decision")}
    ${kpi("good","Approved",all.filter(a=>a.status==="approved").length,"signed off")}
    ${kpi("base","Rejected",all.filter(a=>a.status==="rejected").length,"sent back")}
  </div>
  <div class="card"><div class="seclabel">Pending approvals</div>`;
  if(!pend.length){ h+=`<div class="empty">Nothing awaiting approval. Observations raised by staff, plan completions and status changes appear here for your sign-off.</div>`; }
  else {
    h+=`<table style="margin-top:6px"><thead><tr><th>Type</th><th>Item</th><th>Requested by</th><th>Requested</th><th style="text-align:right">Decision</th></tr></thead><tbody>`+
      pend.map(a=>`<tr>
        <td><span class="tag">${esc(approvalKindLabel(a.kind))}</span></td>
        <td><b>${esc(approvalItemTitle(a))}</b>${a.newStatus?`<div class="hint">→ ${esc(a.newStatus)}</div>`:""}</td>
        <td>${esc(a.requestedByName||"—")}</td>
        <td>${a.requestedAt?esc(fmtDateTime(a.requestedAt)):"—"}</td>
        <td style="text-align:right;white-space:nowrap"><button class="btn sm" onclick="approveAny('${a.id}')">Approve</button> <button class="btn ghost sm danger" onclick="rejectAny('${a.id}')">Reject</button></td>
      </tr>`).join("")+`</tbody></table>`;
  }
  h+=`</div>`;
  if(decided.length){
    h+=`<div class="card"><div class="seclabel">Recent decisions</div>
      <table style="margin-top:6px"><thead><tr><th>Type</th><th>Item</th><th>Requested by</th><th>Decision</th><th>Decided by</th><th>When</th></tr></thead><tbody>`+
      decided.map(a=>`<tr>
        <td><span class="tag">${esc(approvalKindLabel(a.kind))}</span></td>
        <td>${esc(approvalItemTitle(a))}</td>
        <td>${esc(a.requestedByName||"—")}</td>
        <td>${a.status==="approved"?`<span class="pill c-Low">Approved</span>`:`<span class="pill c-Critical">Rejected</span>`}</td>
        <td>${esc(a.decidedByName||"—")}</td>
        <td>${a.decidedAt?esc(fmtDateTime(a.decidedAt)):"—"}</td>
      </tr>`).join("")+`</tbody></table></div>`;
  }
  return h;
}
