  const reports=[]; DB.audits.forEach(a=>a.reports.forEach(r=>reports.push({a,r})));
  if(!reports.length){ openModal("No report available",`<p>Create an audit and report first (Audits &amp; Reports), then raise this finding into it.</p>`,`<button class="btn sec" onclick="closeModal()">Close</button>`); return; }
