  if(p.proposedSummary||(p.proposedSteps||[]).length){
    inner+=`<h2>Proposed Updated Process</h2>${p.proposedSummary?`<div>${esc(p.proposedSummary).replace(/\n/g,"<br>")}</div>`:""}`;
    if((p.proposedSteps||[]).length){ inner+=`<table><tr><th>#</th><th>Actor</th><th>Type</th><th>Action</th><th>Note</th></tr>${p.proposedSteps.map((s,i)=>`<tr><td>${i+1}</td><td>${esc(s.actor||"")}</td><td>${esc(s.type||"")}</td><td>${esc(s.action||"")}</td><td>${esc(s.note||"")}</td></tr>`).join("")}</table><div class="meta">A visual process flowchart is available in the app (Process Review → Download chart).</div>`; }
  }
