async function generateProposedProcess(pid){
  const p=procList().find(x=>x.id===pid); if(!p)return;
  if(_aiBusy) return;
  showAiErr("ppErr","");
  aiBusy(true);
  try{
    const findingsList=(p.findings||[]).map(x=>`- [${x.category}] ${x.title}: ${x.recommendation||x.detail}`).join("\n")||"(no findings captured)";
    const fd=new FormData();
    fd.append("unit", p.unit||"");
    fd.append("sopTitle", p.sopTitle||"");
    fd.append("findings", findingsList);
    if(p.sopPdfBase64) fd.append("pdfBase64", p.sopPdfBase64);
    const res=await fetch("/api/process/propose",{ method:"POST", body:fd });
    const data=await res.json().catch(()=>({}));
    if(!res.ok) throw new Error(data.error||"Could not generate process.");
    doImportProposed(pid, data.analysis);
  }catch(e){
    showAiErr("ppErr", e.message);
  }finally{
    aiBusy(false);
  }
}
function doImportProposed(pid,raw){
  const p=procList().find(x=>x.id===pid); if(!p)return false;
  if(raw==null) raw=val("pp_json").trim(); else if(typeof raw==="object") raw=importRaw(raw); else raw=importRaw(raw);
  if(!raw){ showAiErr("ppErr","Nothing to import."); return false; }
  let d; try{ d=typeof raw==="string"?parseAiJson(raw):raw; }catch(e){ showAiErr("ppErr",e.message); return false; }
  p.proposedSummary=d.proposedSummary||d.summary||"";
  const types=["start","step","control","decision","end"];
  p.proposedSteps=(Array.isArray(d.steps)?d.steps:[]).map(s=>({id:uid(),actor:s.actor||"",action:s.action||"",type:types.includes(String(s.type||"").toLowerCase())?String(s.type).toLowerCase():"step",note:s.note||""}));
  save(); closeModal(); render(); return true;
}
function modalProcStep(pid,sid){
  const p=procList().find(x=>x.id===pid); if(!p)return; p.proposedSteps=p.proposedSteps||[];
  const s=sid?p.proposedSteps.find(y=>y.id===sid):{actor:"",action:"",type:"step",note:""};
  const types=["start","step","control","decision","end"];
  openModal(sid?"Edit step":"Add step",`
    <div class="f2"><div><label>Actor / role</label><input id="ps_actor" value="${esc(s.actor)}"></div>
    <div><label>Type</label><select id="ps_type">${types.map(t=>`<option value="${t}"${s.type===t?" selected":""}>${t.charAt(0).toUpperCase()+t.slice(1)}</option>`).join("")}</select></div></div>
    <label>Action *</label><textarea id="ps_action">${esc(s.action)}</textarea>
    <label>Note <span class="hint">(decision branch / control purpose)</span></label><input id="ps_note" value="${esc(s.note||"")}">`,
    `<button class="btn sec" onclick="closeModal()">Cancel</button>${sid?`<button class="btn sec" onclick="moveProcStep('${pid}','${sid}',-1)">↑</button><button class="btn sec" onclick="moveProcStep('${pid}','${sid}',1)">↓</button>`:""}<button class="btn" onclick="saveProcStep('${pid}','${sid||""}')">Save</button>`);
}
function saveProcStep(pid,sid){ const p=procList().find(x=>x.id===pid); if(!p)return; p.proposedSteps=p.proposedSteps||[]; const action=val("ps_action"); if(!action){toast("Action required");return;} const data={actor:val("ps_actor"),type:val("ps_type"),action,note:val("ps_note")}; if(sid){ Object.assign(p.proposedSteps.find(y=>y.id===sid),data); } else { p.proposedSteps.push({id:uid(),...data}); } save(); closeModal(); render(); }
function delProcStep(pid,sid){ if(!confirm("Delete this step?"))return; const p=procList().find(x=>x.id===pid); if(!p)return; p.proposedSteps=(p.proposedSteps||[]).filter(y=>y.id!==sid); save(); render(); }
function moveProcStep(pid,sid,dir){ const p=procList().find(x=>x.id===pid); if(!p)return; const a=p.proposedSteps||[]; const i=a.findIndex(y=>y.id===sid); const j=i+dir; if(i<0||j<0||j>=a.length)return; const t=a[i]; a[i]=a[j]; a[j]=t; save(); render(); modalProcStep(pid,sid); }

