const STD_CONF=["Not rated","Conforms","Partially Conforms","Does Not Conform"];
const CONF_HEX={"Conforms":"#2e7d32","Generally Conforms":"#2e7d32","Partially Conforms":"#c9a300","Does Not Conform":"#b00020","Not rated":"#94a3b8"};
const IASA_CONF=STD_CONF; const IASA_CONF_HEX=CONF_HEX; // legacy aliases
const MATURITY=["—","1 · Initial","2 · Developing","3 · Established","4 · Managed","5 · Optimised"];
const GIAS_DOMAINS=GIAS.map(g=>({d:g.d+" · "+g.dt,ps:g.ps.map(p=>[p.n,p.t])})); // legacy shape
let iasaMode="assessment";
function iaSA(){ const s=DB.iaSA=DB.iaSA||{}; s.period=s.period||""; s.assessor=s.assessor||""; s.scope=s.scope||""; s.approach=s.approach||""; s.lastEQA=s.lastEQA||""; s.commentary=s.commentary||""; s.items=s.items||{}; s.std=s.std||{}; return s; }
function allPrinc(){ return GIAS.flatMap(g=>g.ps.map(p=>({n:p.n,t:p.t,d:g.d,dt:g.dt,s:p.s}))); }
function allPrinciples(){ return allPrinc().map(p=>({n:p.n,t:p.t,d:p.d+" · "+p.dt})); } // legacy
function allStandards(){ return GIAS.flatMap(g=>g.ps.flatMap(p=>p.s.map(([num,title])=>({num,title,pn:p.n,pt:p.t,d:g.d,dt:g.dt})))); }
function findPrinc(pn){ return allPrinc().find(p=>p.n===+pn); }
function sclip(x,n){ x=String(x||""); return x.length>n?x.slice(0,n-1)+"…":x; }
function iasaSet(n,field,v){ const sa=iaSA(); sa.items[n]=sa.items[n]||{}; sa.items[n][field]=(field==="maturity")?(+v||0):v; save(); render(); }
function stdItem(num){ return iaSA().std[num]||{}; }
function stdConf(num){ return stdItem(num).conf||"Not rated"; }
function stdSet(num,field,v){ const s=iaSA(); s.std[num]=s.std[num]||{}; s.std[num][field]=v; save(); render(); }
function princMaturity(pn){ return +((iaSA().items[pn]||{}).maturity)||0; }
function rollupPrinc(pn){
  const p=findPrinc(pn); if(!p) return "Not rated";
  const rated=p.s.map(([num])=>stdConf(num)).filter(c=>c!=="Not rated");
  if(!rated.length){ const legacy=(iaSA().items[pn]||{}).conformance; if(legacy==="Conforms")return "Generally Conforms"; if(legacy==="Partially Conforms"||legacy==="Does Not Conform")return legacy; return "Not rated"; }
  const dnc=rated.filter(c=>c==="Does Not Conform").length, pc=rated.filter(c=>c==="Partially Conforms").length;
  if(dnc>rated.length/2) return "Does Not Conform";
  if(dnc>0||pc>0) return "Partially Conforms";
  return "Generally Conforms";
}
function overallOpinion(){
  const prs=allPrinc().map(p=>rollupPrinc(p.n)).filter(c=>c!=="Not rated");
  if(!prs.length) return "Not yet assessed";
  if(prs.every(c=>c==="Generally Conforms")) return "Generally Conforms";
  if(prs.filter(c=>c==="Does Not Conform").length>=3) return "Does Not Conform";
  return "Partially Conforms";
}
function eqaDue(){
  const sa=iaSA(); const m=sa.lastEQA&&String(sa.lastEQA).match(/\d{4}/); const yr=m?+m[0]:null;
  const now=(DB.planYear&&+DB.planYear)||(new Date()).getFullYear();
  if(!yr) return {txt:"Not on record",sub:"5-yearly EQA required (Std 8.4)",tone:"mid"};
  const due=yr+5, left=due-now;
  if(left<=0) return {txt:"Due / overdue",sub:"Last EQA "+yr+" · 5-yr cycle reached",tone:"bad"};
  return {txt:"Due "+due,sub:left+" yr(s) left · last EQA "+yr,tone:left<=1?"mid":"good"};
}
function iasaStats(){
  const stds=allStandards(); const total=stds.length;
  const cnt={"Conforms":0,"Partially Conforms":0,"Does Not Conform":0}; let rated=0;
  stds.forEach(s=>{ const c=stdConf(s.num); if(c!=="Not rated"){rated++; if(cnt[c]!=null)cnt[c]++;} });
  const prc={"Generally Conforms":0,"Partially Conforms":0,"Does Not Conform":0}; let pRated=0;
  allPrinc().forEach(p=>{ const c=rollupPrinc(p.n); if(c!=="Not rated"){pRated++; if(prc[c]!=null)prc[c]++;} });
  const matVals=allPrinc().map(p=>princMaturity(p.n)).filter(v=>v>=1);
  const avgMat=matVals.length?matVals.reduce((a,b)=>a+b,0)/matVals.length:0;
  return {total,rated,cnt,prc,pRated,avgMat};
}
function opTone(op){ return op==="Generally Conforms"?"good":op==="Partially Conforms"?"mid":op==="Does Not Conform"?"bad":"base"; }
