function extSetStatus(id,v){ const f=extList().find(x=>x.id===id); if(!f)return; if(v==="Closed"&&!f.closedDateISO)f.closedDateISO=isoNow(); if(v!=="Closed")f.closedDateISO=""; f.status=v; save(); render(); }
function extInsights(){
  const F=extList();
  const themeC={}; F.forEach(f=>{ const t=f.theme||"Other"; themeC[t]=(themeC[t]||0)+1; });
  const themeRows=Object.entries(themeC).sort((a,b)=>b[1]-a[1]); const maxTheme=Math.max(1,...themeRows.map(r=>r[1]));
  const srcs={}; F.forEach(f=>{ const s=f.source||"Other"; (srcs[s]=srcs[s]||{t:0,closed:0,overdue:0}).t++; if(f.status==="Closed")srcs[s].closed++; if(extOverdue(f))srcs[s].overdue++; });
  const srcRows=Object.entries(srcs).sort((a,b)=>b[1].t-a[1].t); const topSrc=srcRows.slice(0,6).map(r=>r[0]);
  const heat={}; F.forEach(f=>{ const t=f.theme||"Other",s=f.source||"Other"; (heat[t]=heat[t]||{})[s]=((heat[t]||{})[s]||0)+1; });
  const maxHeat=Math.max(1,...themeRows.map(([t])=>Math.max(0,...topSrc.map(s=>(heat[t]&&heat[t][s])||0))));
  const clusters=clusterExt(F);
  const obs=allObs();
  const cross=F.map(f=>{ let bs=0,best=null; obs.forEach(o=>{ const s=repSim(f.title,o.title).score; if(s>bs){bs=s;best=o;} }); return {f,best,bs}; });
  const covered=cross.filter(c=>c.bs>=0.4); const blind=cross.filter(c=>c.bs<0.4);
  let h=`<div class="row" style="margin-bottom:14px"><div style="font-size:13px;color:var(--muted)">Strategic view of external &amp; regulatory findings.</div><div class="spacer"></div>
    <button class="btn ghost sm ai-generate-btn" onclick="modalExtCommentary()">Generate insight commentary</button></div>
  ${DB.extCommentary?`<div class="note">${esc(DB.extCommentary)}</div>`:""}
  <div class="card"><div class="seclabel">Recurring areas of concern (by theme)</div>
    ${themeRows.map(([t,v])=>`<div class="rcrow"><div class="nm">${esc(t)}</div><div class="track"><div class="fill" style="width:${v/maxTheme*100}%"></div></div><div class="vv">${v}</div></div>`).join("")}
  </div>
  <div class="card"><div class="seclabel">Theme × source heat map</div>
    <table class="hm"><thead><tr><th class="axis">Theme</th>${topSrc.map(s=>`<th title="${esc(s)}">${esc(s.length>14?s.slice(0,13)+"…":s)}</th>`).join("")}<th>Total</th></tr></thead><tbody>
      ${themeRows.map(([t,tot])=>`<tr><td class="axis">${esc(t)}</td>${topSrc.map(s=>{ const n=(heat[t]&&heat[t][s])||0; const bg=n?hx2rgba("#b00020",0.14+0.8*(n/maxHeat)):"#f7f9fb"; return `<td class="cell" style="background:${bg};color:${n&&(n/maxHeat)>0.55?"#fff":"#1c2733"}">${n||""}</td>`; }).join("")}<td class="cell" style="background:#f1f5f9"><b>${tot}</b></td></tr>`).join("")}
    </tbody></table>
  </div>
  <div class="card"><div class="seclabel">Source scorecard</div>
    <table><thead><tr><th>External body</th><th>Findings</th><th>Closed</th><th>Closure rate</th><th>Overdue</th></tr></thead><tbody>
      ${srcRows.map(([s,v])=>`<tr><td>${esc(s)}</td><td>${v.t}</td><td>${v.closed}</td><td>${Math.round(v.closed/v.t*100)}%</td><td>${v.overdue?`<span class="pill c-High">${v.overdue}</span>`:"—"}</td></tr>`).join("")}
    </tbody></table>
  </div>
  <div class="card"><div class="seclabel">Repeat / recurring findings</div>
    ${clusters.length?clusters.map(cl=>`<div class="obs-block" style="padding:11px 13px;margin-bottom:10px;background:#f3eef8;border-color:#d4c4e8">
      <div class="row"><b style="flex:1">${esc(cl.rep)}</b><span class="pill" style="background:#efe3f7;color:#6b3fa0">×${cl.items.length}</span></div>
      <div class="hint" style="margin-top:5px">Raised by: ${cl.items.map(i=>esc(i.source||"?")+(i.year?" "+esc(i.year):"")).filter((v,ix,ar)=>ar.indexOf(v)===ix).join(" · ")}</div></div>`).join("")
      :`<div class="hint">No recurring findings detected yet (auto-detected by fuzzy match). Flag known repeats on each finding, or they'll cluster here as more are added.</div>`}
  </div>
  <div class="card"><div class="seclabel">Internal Audit coverage cross-reference</div>
    <div class="row" style="gap:18px"><div><div style="font-size:30px;font-weight:700;color:#2e7d32">${covered.length}</div><div class="hint">also identified by Internal Audit<br>(validates IA coverage)</div></div>
      <div><div style="font-size:30px;font-weight:700;color:var(--crit)">${blind.length}</div><div class="hint">not matched to an IA observation<br>(potential coverage gap)</div></div></div>
    ${blind.length?`<div class="seclabel" style="margin-top:14px">Potential coverage gaps</div><table><thead><tr><th>Source</th><th>Finding</th><th>Theme</th></tr></thead><tbody>${blind.slice(0,10).map(c=>`<tr><td>${esc(c.f.source||"—")}</td><td>${esc(c.f.title)}</td><td>${esc(c.f.theme||"—")}</td></tr>`).join("")}</tbody></table>${blind.length>10?`<div class="hint" style="margin-top:6px">Showing 10 of ${blind.length}.</div>`:""}`:""}
    <div class="hint" style="margin-top:8px">Matched by fuzzy title similarity to your internal observations — indicative, review before relying on it.</div>
  </div>`;
  return h;
}
function clusterExt(F){
  const items=F.filter(f=>(f.title||"").trim().length>6); const used=new Array(items.length).fill(false); const cl=[];
  for(let i=0;i<items.length;i++){ if(used[i])continue; const g=[items[i]]; used[i]=true;
    for(let j=i+1;j<items.length;j++){ if(used[j])continue; const s=repSim(items[i].title,items[j].title); if(s.score>=0.42||s.dice>=0.6){ g.push(items[j]); used[j]=true; } }
    if(g.length>=2||items[i].isRepeat) cl.push({rep:items[i].title.length>150?items[i].title.slice(0,149)+"…":items[i].title,items:g}); }
  return cl.sort((a,b)=>b.items.length-a.items.length).slice(0,8);
}
