async function generateExtFindings(){
  const src=val("xi_src"), sref=val("xi_sref"), text=val("xi_text");
  if(!text){ showAiErr("xi_err","Paste the report text first."); return; }
  await runAiJson(buildExtPrompt(src,sref,text),"xi_err",d=>{ doImportExtJSON(d); });
}
function doImportExtJSON(raw){
  const F=extList(); raw=importRaw(raw);
  if(!raw){ showAiErr("xi_err","Nothing to import."); return false; }
  let d; try{ d=parseAiJson(raw); }catch(e){ showAiErr("xi_err",e.message); return false; }
  const arr=Array.isArray(d)?d:[d]; const src=val("xi_src"), sref=val("xi_sref"); let n=0;
  arr.forEach(x=>{ if(x&&typeof x==="object"&&(x.title||x.finding)){ F.push(extNormalize(x,src,sref)); n++; } });
  if(!n){ showAiErr("xi_err","No findings found in that JSON."); return false; }
  save(); closeModal(); render(); return true;
}
function extNormalize(x,src,sref){
  const theme=EXT_THEMES.find(t=>t.toLowerCase()===String(x.theme||"").toLowerCase())||"Other";
  const sev=["High","Medium","Low"].find(s=>s.toLowerCase()===String(x.severity||"").toLowerCase())||"Medium";
  const source=EXT_SOURCES.find(s=>s.toLowerCase()===String(x.source||src||"").toLowerCase())||(x.source||src||"Other");
  const st=STATUSES.find(s=>s.toLowerCase()===String(x.status||"").toLowerCase())||"Open";
  return {id:uid(),source,sourceRef:x.sourceRef||sref||"",year:x.year?String(x.year):"",ref:x.ref||"",title:x.title||x.finding||"(untitled)",detail:x.detail||x.description||"",risk:x.risk||x.impact||"",recommendation:x.recommendation||"",theme,severity:sev,owner:x.owner||"",targetDate:x.targetDate||x.target||"",status:st,managementResponse:x.managementResponse||x.response||"",isRepeat:!!x.isRepeat,repeatOf:x.repeatOf||"",closedDateISO:st==="Closed"?isoNow():"",createdAt:new Date().toISOString()};
}
function downloadExtTemplate(){
  const headers=["Source","SourceRef","Year","Ref","Title","Detail","Risk","Recommendation","Theme","Severity","Owner","TargetDate","Status","ManagementResponse","IsRepeat","RepeatOf"];
  const ex=["Statutory / External Audit","2024 Statutory Management Letter","2024","3.2","Weak IT access controls over the loan management system","Privileged access not periodically reviewed; leavers retained access.","Unauthorised access and data integrity risk.","Implement quarterly user-access reviews and prompt de-provisioning of leavers.","Access & IT security","High","Head, IT","30 Sep 2026","Open","No",""];
  dl(headers.join(",")+"\n"+ex.map(csvEsc).join(",")+"\n","external-findings-template.csv","text/csv");
}
function doImportExtCSV(){
  const F=extList(); const err=document.getElementById("xi_cerr"); const text=val("xi_csv");
  if(!text){ err.textContent="Paste or load CSV first."; return; }
  const rows=parseCSV(text).filter(r=>r.some(c=>String(c).trim()!==""));
  if(rows.length<2){ err.textContent="Need a header row plus at least one finding."; return; }
  const H=rows[0].map(h=>String(h).toLowerCase().replace(/[^a-z0-9]/g,""));
  const M={source:"source",sourceref:"sourceRef",report:"sourceRef",year:"year",ref:"ref",sn:"ref",title:"title",finding:"title",observation:"title",detail:"detail",description:"detail",risk:"risk",impact:"risk",recommendation:"recommendation",theme:"theme",category:"theme",severity:"severity",rating:"severity",owner:"owner",targetdate:"targetDate",duedate:"targetDate",status:"status",managementresponse:"managementResponse",response:"managementResponse",isrepeat:"isRepeat",repeat:"isRepeat",repeatof:"repeatOf"};
  const idx={}; H.forEach((h,i)=>{ if(M[h]!=null&&idx[M[h]]==null) idx[M[h]]=i; });
  if(idx.title==null){ err.textContent="CSV must include a Title column."; return; }
  let n=0; for(let r=1;r<rows.length;r++){ const cols=rows[r]; const g=k=>idx[k]!=null?String(cols[idx[k]]==null?"":cols[idx[k]]).trim():"";
    if(!g("title"))continue;
    const x={source:g("source"),sourceRef:g("sourceRef"),year:g("year"),ref:g("ref"),title:g("title"),detail:g("detail"),risk:g("risk"),recommendation:g("recommendation"),theme:g("theme"),severity:g("severity"),owner:g("owner"),targetDate:g("targetDate"),status:g("status"),managementResponse:g("managementResponse"),isRepeat:/^(y|yes|true|1)$/i.test(g("isRepeat")),repeatOf:g("repeatOf")};
    F.push(extNormalize(x,g("source"),g("sourceRef"))); n++;
  }
  if(!n){ err.textContent="No findings found in the CSV."; return; }
  save(); closeModal(); render(); toast(n+" external finding(s) imported.","success");
}
