  h+=sumSection("1.3 Areas for strategic improvement", bullets(r.areasForImprovement));
  h+=sumSection("1.4 Internal audit opinion"+(r.assuranceLevel?` <span class="tag">${esc(r.assuranceLevel)}</span>`:""), txt(r.auditOpinion));
