    !o.ownerRectifiedAt ? "Awaiting the action owner's response." :
    !o.reportVerifiedAt ? "Awaiting auditor verification." : "Awaiting Head of Audit closure.";
  const composerTitle=owner?"Your response":"Add a comment";
