function downloadObsTemplate(){
  const headers=["Audit","AuditType","Area","Report","Ref","Title","Criticality","Category","Description","Criteria","Risk","RootCause","Recommendation","ProposedSOP","ManagementResponse","Owner","Timeline","DueDate","Status","IsRepeat","RepeatOf"];
  const ex=["Credit Operations Audit 2025","Process","Credit Operations","Loan Origination Controls Review","1.1","Loan disbursements approved without credit committee sign-off","High","Authorisation","Funds were released without documented Credit Committee approval for sampled disbursements.","Credit Policy requires committee approval before disbursement.","Elevated credit loss, fraud and regulatory exposure.","Disbursement system does not enforce approval as a hard control.","Configure the system to block disbursement until approval is recorded; enforce segregation of duties.","Section 4.2 of the Loan Disbursement SOP shall be revised to read: 'No disbursement may be initiated until a valid Credit Committee approval reference is recorded in the core system, and the officer who approves a facility shall not initiate its disbursement.'","NDA executed; system control to be configured.","Head, Credit Operations","Immediate","31 Aug 2026","Open","No",""];
  const q=v=>{ v=String(v==null?"":v); return /[",\n]/.test(v)?'"'+v.replace(/"/g,'""')+'"':v; };
  const csv=headers.join(",")+"\n"+ex.map(q).join(",")+"\n";
  dl(csv,"observations-import-template.csv","text/csv");
}
function loadCsvFile(e){ const f=e.target.files[0]; if(!f)return; const rd=new FileReader(); rd.onload=()=>{ const el=document.getElementById("bulkCsv"); if(el) el.value=rd.result; }; rd.readAsText(f); }
function parseCSV(text){
  text=text.replace(/^﻿/,"").replace(/\r\n/g,"\n").replace(/\r/g,"\n");
  const rows=[]; let row=[],field="",inQ=false,i=0;
  while(i<text.length){ const ch=text[i];
    if(inQ){ if(ch==='"'){ if(text[i+1]==='"'){ field+='"'; i+=2; continue; } inQ=false; i++; continue; } field+=ch; i++; continue; }
    if(ch==='"'){ inQ=true; i++; continue; }
    if(ch===','){ row.push(field); field=""; i++; continue; }
    if(ch==='\n'){ row.push(field); rows.push(row); row=[]; field=""; i++; continue; }
    field+=ch; i++;
  }
  if(field!==""||row.length){ row.push(field); rows.push(row); }
  return rows;
}
function normCrit(s){ s=(s||"").trim(); if(!s)return "Moderate"; if(/^med/i.test(s))return "Moderate"; if(/^pi$|^proc|improv/i.test(s))return "Process Improvement"; return CRITS.find(c=>c.toLowerCase()===s.toLowerCase())||"Moderate"; }
function findOrCreateAudit(name,type,area){
  let a=DB.audits.find(x=>x.name.toLowerCase().trim()===name.toLowerCase().trim());
  if(!a){ a={id:uid(),name:name.trim(),type:(type&&/^dep/i.test(type.trim()))?"department":"process",area:area||"",period:"",leadAuditor:"",status:"In progress",createdAt:new Date().toISOString(),reports:[]}; DB.audits.push(a); }
  else if(area && !a.area){ a.area=area; }
  return a;
}
function findOrCreateReport(a,title){
  let r=a.reports.find(x=>x.title.toLowerCase().trim()===title.toLowerCase().trim());
  if(!r){ r={id:uid(),title:title.trim(),refNo:"",period:a.period||"",status:"Draft",scope:"",createdAt:new Date().toISOString(),observations:[]}; a.reports.push(r); }
  return r;
}
function doBulkImport(){
  const text=val("bulkCsv"); const out=document.getElementById("bulkOut");
  const err=m=>{ out.innerHTML=`<div class="hint" style="color:var(--crit)">${m}</div>`; };
  if(!text){ err("Paste CSV or load a file first."); return; }
  const rows=parseCSV(text).filter(r=>r.some(c=>String(c).trim()!==""));
  if(rows.length<2){ err("No data rows found — need a header row plus at least one observation."); return; }
  const headers=rows[0].map(h=>String(h).toLowerCase().replace(/[^a-z0-9]/g,""));
  const HMAP={audit:"audit",audittype:"type",type:"type",area:"area",processdepartment:"area",department:"area",report:"report",ref:"ref",sn:"ref",title:"title",observation:"title",criticality:"criticality",rating:"criticality",category:"category",controltheme:"category",description:"description",detaileddescription:"description",condition:"description",criteria:"criteria",risk:"risk",impact:"risk",impactrisk:"risk",rootcause:"rootCause",cause:"rootCause",recommendation:"recommendation",proposedsop:"sopUpdate",sopupdate:"sopUpdate",proposedsopupdate:"sopUpdate",managementresponse:"managementResponse",mgmtresponse:"managementResponse",remediationaction:"managementResponse",owner:"owner",actionowner:"owner",timeline:"timeline",resolutiontimeline:"timeline",duedate:"dueDate",targetdate:"dueDate",agreedtarget:"dueDate",status:"status",isrepeat:"isRepeat",repeat:"isRepeat",repeatof:"repeatOf"};
  const idx={}; headers.forEach((h,i)=>{ if(HMAP[h]!=null && idx[HMAP[h]]==null) idx[HMAP[h]]=i; });
  if(idx.audit==null||idx.report==null||idx.title==null){ err("CSV must include <b>Audit</b>, <b>Report</b> and <b>Title</b> columns. Download the template for the exact headers."); return; }
  let imported=0; const skipped=[];
  for(let r=1;r<rows.length;r++){
    const cols=rows[r]; const g=k=>idx[k]!=null?String(cols[idx[k]]==null?"":cols[idx[k]]).trim():"";
    const auditName=g("audit"), reportTitle=g("report"), title=g("title");
    if(!auditName||!reportTitle||!title){ skipped.push("Row "+(r+1)+": missing Audit / Report / Title"); continue; }
    const a=findOrCreateAudit(auditName,g("type"),g("area"));
    const rep=findOrCreateReport(a,reportTitle);
    let tlRaw=g("timeline").replace(/\s+/g,"-");
    const tl=TIMELINES.find(t=>t.toLowerCase()===tlRaw.toLowerCase())||"";
    const stRaw=g("status");
    const st=STATUSES.find(s=>s.toLowerCase()===stRaw.toLowerCase())||(/(progress|wip|ongoing)/i.test(stRaw)?"In Progress":/(clos|done|resolved|mitigat|complete)/i.test(stRaw)?"Closed":"Open");
    const o={id:uid(),ref:g("ref"),title,category:g("category"),description:g("description"),criteria:g("criteria"),risk:g("risk"),rootCause:g("rootCause"),recommendation:g("recommendation"),sopUpdate:g("sopUpdate"),criticality:normCrit(g("criticality")),managementResponse:g("managementResponse"),owner:g("owner"),timeline:tl,dueDate:g("dueDate"),isRepeat:/^(y|yes|true|1)$/i.test(g("isRepeat")),repeatOf:g("repeatOf"),status:st,createdAt:new Date().toISOString()};
    if(st==="Closed") o.closedDateISO=isoNow();
    rep.observations.push(o); imported++;
  }
  save();
  out.innerHTML=`<div class="note">Imported <b>${imported}</b> observation(s)${skipped.length?`; skipped ${skipped.length}`:""}.</div>`+(skipped.length?`<div class="hint">${skipped.slice(0,12).map(esc).join("<br>")}${skipped.length>12?"<br>…":""}</div>`:"")+(imported?`<div class="row" style="margin-top:8px"><button class="btn sm" onclick="go('audits')">View Audits &amp; Reports</button> <button class="btn sm sec" onclick="go('dashboard')">View Dashboard</button></div>`:"");
}
function buildObsPrompt(ol,area,ctx){
  return `Act as my internal audit observation drafter for ${DB.org}. Expand the one-liner below into a formal audit observation using the 5C structure. Recommend a criticality using this rubric:
${CRITS.map(c=>`- ${c}: ${RUBRIC[c]}`).join("\n")}

One-liner: ${ol}
Process / Department: ${area||"(not specified)"}
Context: ${ctx||"(not specified)"}

Return ONLY a JSON object (no commentary) with these exact keys — every field must be populated with substantive content:
{
  "ref": "observation reference e.g. 1.1",
  "title": "concise observation title",
  "category": "control theme, e.g. Credit risk / Segregation of duties",
  "description": "detailed condition — what was observed, with specifics",
  "criteria": "the policy/standard/expectation that was not met",
  "risk": "impact & risk if not addressed",
  "rootCause": "most likely root cause(s)",
  "recommendation": "specific, actionable recommendation per best practice",
  "criticality": "Critical | High | Moderate | Low | Process Improvement",
  "owner": "the role/function best placed to own remediation, e.g. Head, Credit Operations",
  "timeline": "Immediate | Short-term | Long-term",
  "agreedTarget": "a realistic proposed agreed remediation target — a date or timeframe consistent with the timeline, e.g. 'Complete by 30 Sep 2026' or 'within 60 days'"
}`;
}
async function generateObsFromPicker(){
  const ol=document.getElementById("ol")&&document.getElementById("ol").value.trim();
  const area=document.getElementById("olArea")&&document.getElementById("olArea").value.trim();
  const ctx=document.getElementById("olCtx")&&document.getElementById("olCtx").value.trim();
  const v=document.getElementById("tgtReport")&&document.getElementById("tgtReport").value;
  if(!ol){ showAiErr("obsGenErr","Enter your one-liner first."); return; }
  if(!v){ showAiErr("obsGenErr","Choose a target report."); return; }
  const [aid,rid]=v.split("|");
  await runAiJson(buildObsPrompt(ol,area,ctx),"obsGenErr",d=>{ doImport(aid,rid,d,"obsGenErr"); });
}
function modalGenerateObs(aid,rid){
  openModal("Generate observation",`
    <label>One-liner observation</label>
    <input id="go_ol" placeholder="e.g. Loan disbursements approved without credit committee sign-off">
    <label>Additional context (optional)</label>
    <textarea id="go_ctx" style="min-height:80px" placeholder="Any extra detail to steer the draft — prior findings, system, timing…"></textarea>
    <div id="go_err" style="margin-top:10px"></div>`,
    `<button class="btn sec" onclick="closeModal()">Cancel</button><button class="btn dark ai-generate-btn" onclick="generateObsForReport('${aid}','${rid}')">Generate observation</button>`);
}
async function generateObsForReport(aid,rid){
  const ol=val("go_ol"), ctx=val("go_ctx");
  if(!ol){ showAiErr("go_err","Enter a one-liner first."); return; }
  const a=audit(aid);
  await runAiJson(buildObsPrompt(ol,a&&a.area||"",ctx),"go_err",d=>{ doImport(aid,rid,d,"go_err"); });
}
function buildPrompt(){ generateObsFromPicker(); }

